import { Injectable } from '@nestjs/common';
import { InjectModel } from '@nestjs/mongoose';
import { Model, Types } from 'mongoose';
import {
  AuditLogSchemaClass,
  AuditLogDocument,
} from './entities/audit-log.schema';
import { UserSchemaClass } from '../users/infrastructure/persistence/document/entities/user.schema';

@Injectable()
export class AuditLogService {
  constructor(
    @InjectModel(AuditLogSchemaClass.name, 'audit-log-db-connection')
    private readonly model: Model<AuditLogDocument>,
    @InjectModel(UserSchemaClass.name)
    private readonly userModel: Model<any>,
  ) {}

  /**
   * Cursor-based pagination for audit logs.
   *
   * Uses composite cursor { t, _id } to handle:
   * - Duplicate millisecond timestamps (common in batch automation)
   * - O(1) performance via compound index (no .skip())
   */
  async getAuditLogs(params: {
    tenantId: string;
    entityType: string;
    entityId: string;
    limit: number;
    cursor?: string; // base64({ t: ISOString, _id: string })
  }) {
    const { tenantId, entityType, entityId, limit, cursor } = params;
    const where: any = { tenantId, entityType, entityId };

    if (cursor) {
      try {
        const { t, _id } = JSON.parse(Buffer.from(cursor, 'base64').toString());
        const objectId = new Types.ObjectId(_id);
        where.$or = [
          { t: { $lt: new Date(t) } },
          { t: new Date(t), _id: { $lt: objectId } },
        ];
      } catch {
        // Invalid cursor ΓÇö ignore and return from beginning
      }
    }

    const docs = await this.model
      .find(where)
      .sort({ t: -1, _id: -1 })
      .limit(limit + 1)
      .lean();

    const hasMore = docs.length > limit;
    const page = hasMore ? docs.slice(0, limit) : docs;
    const last = page[page.length - 1];
    const nextCursor =
      hasMore && last
        ? Buffer.from(
            JSON.stringify({
              t: last.t instanceof Date ? last.t.toISOString() : last.t,
              _id: last._id.toString(),
            }),
          ).toString('base64')
        : null;

    // ΓöÇΓöÇ Populate actor and referenced user info (batch lookup) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const actorIds = page
      .map((d: any) => d.actorId)
      .filter((id: string) => id && id !== 'system');

    const referencedUserIds: string[] = [];
    for (const entry of page) {
      if (entry.changes && Array.isArray(entry.changes)) {
        for (const change of entry.changes) {
          if (change.f === 'ownerId' || change.f === 'assigneeId') {
            if (
              change.o &&
              typeof change.o === 'string' &&
              change.o !== 'system'
            ) {
              referencedUserIds.push(change.o);
            }
            if (
              change.n &&
              typeof change.n === 'string' &&
              change.n !== 'system'
            ) {
              referencedUserIds.push(change.n);
            }
          }
        }
      }
    }

    const allUserIds = [...actorIds, ...referencedUserIds].filter(
      (value, index, self) => self.indexOf(value) === index,
    );

    const userMap: Record<
      string,
      { firstName?: string; lastName?: string; email?: string; photo?: any }
    > = {};
    if (allUserIds.length > 0) {
      try {
        const validIds = allUserIds
          .filter((id) => Types.ObjectId.isValid(id as string))
          .map((id) => new Types.ObjectId(id as string));

        if (validIds.length > 0) {
          const users = (await this.userModel
            .find(
              { _id: { $in: validIds } },
              { firstName: 1, lastName: 1, email: 1, photo: 1 },
            )
            .lean()) as Array<{
            _id: any;
            firstName?: string;
            lastName?: string;
            email?: string;
            photo?: any;
          }>;

          for (const u of users) {
            userMap[u._id.toString()] = {
              firstName: u.firstName,
              lastName: u.lastName,
              email: u.email,
              photo: u.photo,
            };
          }
        }
      } catch (err) {
        console.error('[AuditLogService] User lookup failed:', err?.message);
      }
    }

    const enriched = page.map((entry: any) => {
      const actor = userMap[entry.actorId];
      // Destructure to separate _id and __v from rest to avoid ObjectId serialization issues
      const { _id, __v, changes, ...rest } = entry;
      const idStr = typeof _id === 'string' ? _id : String(_id);

      const enrichedChanges = (changes || []).map((change: any) => {
        if (change.f === 'ownerId' || change.f === 'assigneeId') {
          const oldUser = change.o ? userMap[String(change.o)] : null;
          const newUser = change.n ? userMap[String(change.n)] : null;

          return {
            ...change,
            o: oldUser
              ? [oldUser.firstName, oldUser.lastName]
                  .filter(Boolean)
                  .join(' ') || oldUser.email
              : change.o,
            n: newUser
              ? [newUser.firstName, newUser.lastName]
                  .filter(Boolean)
                  .join(' ') || newUser.email
              : change.n,
          };
        }
        return change;
      });

      return {
        ...rest,
        _id: idStr,
        changes: enrichedChanges,
        actor: actor
          ? {
              name:
                [actor.firstName, actor.lastName].filter(Boolean).join(' ') ||
                actor.email ||
                null,
              email: actor.email || null,
              photo: actor.photo?.url ?? actor.photo ?? null,
            }
          : entry.actorId === 'system'
            ? { name: 'System', email: null, photo: null }
            : { name: null, email: null, photo: null },
      };
    });

    return { data: enriched, nextCursor, hasMore };
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { ulid } from 'ulid';
import { AutomationWorkflowRepository } from '../infrastructure/persistence/document/repositories/automation-workflow.repository';
import { AutomationExecutionLogRepository } from '../infrastructure/persistence/document/repositories/automation-execution-log.repository';
import { ExecutionStep } from '../infrastructure/persistence/document/entities/automation-execution-log.schema';
import {
  ConditionEvaluatorService,
  ConditionGroup,
} from './condition-evaluator.service';
import { LoopPreventionService } from './loop-prevention.service';
import { AutomationActionProducer } from '../queue/automation-action.producer';
import { AutomationDelayedProducer } from '../queue/automation-delayed.producer';
import { AutomationEventPayload } from '../events/automation-event.payload';
import {
  AutomationActionJobData,
  AutomationDelayedJobData,
} from '../queue/automation-queue.constants';
import { WebhookHeaderCryptoService } from './webhook-header-crypto.service';
import {
  WorkflowNode,
  WorkflowEdge,
} from '../infrastructure/persistence/document/entities/automation-workflow.schema';

/** Hard cap on wait-node delays ΓÇö 90 days in milliseconds (MED-04). */
export const MAX_WAIT_DELAY_MS = 90 * 24 * 60 * 60 * 1000;

/**
 * Fields preserved when slimming a record before it is queued / logged.
 * Keeps just what templates and recipient-resolution need, dropping the
 * rest of the record to avoid persisting unnecessary PII (HIGH-07).
 */
const SLIM_RECORD_FIELDS = [
  'id',
  '_id',
  'email',
  'phone',
  'phoneNumber',
  'mobile',
  'firstName',
  'lastName',
  'fullName',
  'name',
] as const;

/**
 * Wait/Delay node configuration schema.
 */
interface WaitNodeConfig {
  name?: string;
  delayType: 'fixed'; // Phase 4.0: fixed delay only
  delayValue: number; // e.g. 30
  delayUnit: 'minutes' | 'hours' | 'days';
}

/**
 * WorkflowOrchestratorService ΓÇö the brain of the Automation Engine.
 *
 * Coordinates the full execution of a workflow for a given record:
 *   1. Loop prevention checks (all 3 layers)
 *   2. Walk the DAG: Trigger ΓåÆ Condition(s) ΓåÆ Action(s) ΓåÆ Wait(s)
 *   3. For condition nodes: evaluate nested AND/OR groups
 *   4. For action nodes: dispatch to BullMQ typed queues
 *   5. For wait nodes: serialize state ΓåÆ delayed queue ΓåÆ stop traversal
 *   6. Write execution logs at each step
 *
 * Supports True/False Split branching on condition nodes.
 * Supports Delay/Wait nodes (Stateful DAG ΓÇö hibernate and resume).
 *
 * @see docs/prd-visual-automation-builder.md ΓÇö Task 1.6
 */
@Injectable()
export class WorkflowOrchestratorService {
  private readonly logger = new Logger(WorkflowOrchestratorService.name);
  constructor(
    private readonly workflowRepo: AutomationWorkflowRepository,
    private readonly executionLogRepo: AutomationExecutionLogRepository,
    private readonly conditionEvaluator: ConditionEvaluatorService,
    private readonly loopPrevention: LoopPreventionService,
    private readonly actionProducer: AutomationActionProducer,
    private readonly delayedProducer: AutomationDelayedProducer,
    private readonly webhookHeaderCrypto: WebhookHeaderCryptoService,
  ) {}

  /**
   * Execute a workflow for a given record.
   * Called from AutomationEventListenerService for each matched workflow.
   */
  async execute(
    workflow: any, // Lean document from findActiveByTrigger
    payload: AutomationEventPayload,
  ): Promise<void> {
    const tenantId = payload.tenantId;
    const workflowId = workflow._id.toString();
    const recordId = payload.recordId;
    const depth = payload.automationDepth ?? 0;
    const breadcrumbs = payload.automationBreadcrumbs ?? [];
    const executionSessionId = ulid();

    this.logger.log(
      `[Orchestrator] Starting workflow "${workflow.name}" (${workflowId}) for record=${recordId} depth=${depth}`,
    );

    // ΓöÇΓöÇ Layer 2: Depth limit check (synchronous) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const depthCheck = this.loopPrevention.checkDepthLimit(depth);
    if (!depthCheck.allowed) {
      this.logger.warn(`[Orchestrator] DEPTH_EXCEEDED: ${depthCheck.reason}`);
      const execLog = await this.executionLogRepo.startExecution({
        tenantId,
        workflowId,
        workflowName: workflow.name,
        recordId,
        recordType: payload.object,
        automationDepth: depth,
      });
      await this.executionLogRepo.blockExecution(execLog._id.toString(), {
        code: 'LOOP_DEPTH_EXCEEDED',
        message: depthCheck.reason!,
      });
      return;
    }

    const breadcrumbCheck = this.loopPrevention.checkBreadcrumbs({
      workflowId,
      breadcrumbs,
    });
    if (!breadcrumbCheck.allowed) {
      this.logger.warn(
        `[Orchestrator] BREADCRUMB_LOOP: ${breadcrumbCheck.reason}`,
      );
      const execLog = await this.executionLogRepo.startExecution({
        tenantId,
        workflowId,
        workflowName: workflow.name,
        recordId,
        recordType: payload.object,
        automationDepth: depth,
      });
      await this.executionLogRepo.blockExecution(execLog._id.toString(), {
        code: 'LOOP_BREADCRUMB_DETECTED',
        message: breadcrumbCheck.reason!,
      });
      return;
    }

    // ΓöÇΓöÇ Layer 3: Run-once check ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    if (workflow.triggerConfig?.runOncePerRecord) {
      const runOnceCheck = await this.loopPrevention.checkRunOnce({
        tenantId,
        workflowId,
        recordId,
      });

      if (!runOnceCheck.allowed) {
        this.logger.debug(
          `[Orchestrator] RUN_ONCE_SKIPPED: ${runOnceCheck.reason}`,
        );
        const execLog = await this.executionLogRepo.startExecution({
          tenantId,
          workflowId,
          workflowName: workflow.name,
          recordId,
          recordType: payload.object,
          automationDepth: depth,
        });
        await this.executionLogRepo.skipExecution(execLog._id.toString());
        return;
      }

      // Mark as executed for future run-once checks
      await this.loopPrevention.markRunOnce({ tenantId, workflowId, recordId });
    }

    // ΓöÇΓöÇ Start execution log ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const execLog = await this.executionLogRepo.startExecution({
      tenantId,
      workflowId,
      workflowName: workflow.name,
      recordId,
      recordType: payload.object,
      automationDepth: depth,
    });
    const executionId = execLog._id.toString();
    const stepLogs: ExecutionStep[] = [];

    try {
      // ΓöÇΓöÇ Walk the DAG (using PUBLISHED snapshot ΓÇö immune to live edits) ΓöÇΓöÇ
      const nodes: any[] = workflow.publishedNodes || [];
      const edges: any[] = workflow.publishedEdges || [];

      // Guard: refuse to execute unpublished workflows
      if (nodes.length === 0) {
        throw new Error(
          'UNPUBLISHED_WORKFLOW: No published nodes found. Workflow must be published before execution.',
        );
      }

      // Find the trigger node (entry point)
      const triggerNode = nodes.find((n: any) => n.type === 'trigger');
      if (!triggerNode) {
        throw new Error('No trigger node found in published workflow');
      }

      // BFS traversal from trigger node
      const hibernated = await this.traverseFromNode(
        triggerNode.id,
        nodes,
        edges,
        payload,
        executionId,
        workflowId,
        tenantId,
        executionSessionId,
        depth,
        stepLogs,
      );

      // ΓöÇΓöÇ Mark success (only if no wait node paused the execution) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

      if (!hibernated) {
        await this.flushStepLogs(executionId, stepLogs);
        await this.executionLogRepo.completeExecution(executionId);
        await this.workflowRepo.incrementExecutionCount(tenantId, workflowId);

        this.logger.log(
          `[Orchestrator] Γ£à Workflow "${workflow.name}" completed for record=${recordId}`,
        );
      } else {
        this.logger.log(
          `[Orchestrator] ΓÅ╕ Workflow "${workflow.name}" hibernated (wait node) ΓÇö will resume later`,
        );
        // Execution stays in "running" status until delayed processor completes it
      }
    } catch (error: any) {
      this.logger.error(
        `[Orchestrator] Γ¥î Workflow "${workflow.name}" failed: ${error.message}`,
        error.stack,
      );
      await this.flushStepLogs(executionId, stepLogs);
      await this.executionLogRepo.failExecution(executionId, {
        code: 'EXECUTION_ERROR',
        message: error.message,
      });
    }
  }

  /**
   * Resume DAG traversal from a specific node.
   * Called by AutomationDelayedProcessor after a wait timer expires.
   *
   * @param nodeId - Node ID to resume from (downstream of the wait node)
   */
  async resumeFromNode(
    nodeId: string,
    nodes: any[],
    edges: any[],
    payload: AutomationEventPayload,
    executionId: string,
    workflowId: string,
    tenantId: string,
    executionSessionId: string,
    depth: number,
  ): Promise<void> {
    const stepLogs: ExecutionStep[] = [];
    try {
      const hibernated = await this.traverseFromNode(
        nodeId,
        nodes,
        edges,
        payload,
        executionId,
        workflowId,
        tenantId,
        executionSessionId,
        depth,
        stepLogs,
      );

      if (!hibernated) {
        // Mark execution as completed after delayed resume finishes
        await this.flushStepLogs(executionId, stepLogs);
        await this.executionLogRepo.completeExecution(executionId);
        await this.workflowRepo.incrementExecutionCount(tenantId, workflowId);

        this.logger.log(
          `[Orchestrator] Γ£à Resumed execution ${executionId} completed`,
        );
      } else {
        this.logger.log(
          `[Orchestrator] Resumed execution ${executionId} hibernated again`,
        );
      }
    } catch (error: any) {
      this.logger.error(
        `[Orchestrator] Γ¥î Resumed execution ${executionId} failed: ${error.message}`,
        error.stack,
      );
      await this.flushStepLogs(executionId, stepLogs);
      await this.executionLogRepo.failExecution(executionId, {
        code: 'RESUME_ERROR',
        message: error.message,
      });
    }
  }

  // ΓöÇΓöÇ DAG Traversal ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  /**
   * Traverse the DAG from a given node.
   * @returns true if a wait/delay node was encountered (execution is hibernated)
   */
  private async traverseFromNode(
    nodeId: string,
    nodes: any[],
    edges: any[],
    payload: AutomationEventPayload,
    executionId: string,
    workflowId: string,
    tenantId: string,
    executionSessionId: string,
    depth: number,
    stepLogs: ExecutionStep[],
  ): Promise<boolean> {
    const node = nodes.find((n: any) => n.id === nodeId);
    if (!node) return false;

    // ΓöÇΓöÇ Layer 0: hard step ceiling (CRIT-04 defense-in-depth) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    // Independent of Redis: bounds total work in a single execution so a cyclic
    // graph that slipped past validation (or a Redis outage disabling the
    // strict-loop guard) can never recurse into a stack overflow.
    const MAX_TOTAL_STEPS = 1000;
    if (stepLogs.length > MAX_TOTAL_STEPS) {
      throw new Error(
        `MAX_STEPS_EXCEEDED: execution processed more than ${MAX_TOTAL_STEPS} steps (possible cycle)`,
      );
    }

    const stepStart = new Date();

    // ΓöÇΓöÇ Layer 1: Strict loop check ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const loopCheck = await this.loopPrevention.checkStrictLoop({
      tenantId,
      executionSessionId,
      nodeId,
    });
    if (!loopCheck.allowed) {
      this.bufferStep(stepLogs, {
        nodeId,
        nodeName: node.config?.name || node.type,
        nodeType: node.type,
        status: 'failed',
        input: {},
        error: {
          code: 'LOOP_STRICT_DETECTED',
          message: loopCheck.reason!,
        },
        startedAt: stepStart,
        completedAt: new Date(),
        duration: Date.now() - stepStart.getTime(),
      });
      throw new Error(`LOOP_STRICT_DETECTED: ${loopCheck.reason}`);
    }

    // ΓöÇΓöÇ Process node by type ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    if (node.type === 'trigger') {
      // Trigger node: just log and move to next
      this.bufferStep(stepLogs, {
        nodeId,
        nodeName: 'Trigger',
        nodeType: 'trigger',
        status: 'success',
        input: { event: payload.event, object: payload.object },
        startedAt: stepStart,
        completedAt: new Date(),
        duration: Date.now() - stepStart.getTime(),
      });

      // Follow all edges from trigger
      const nextEdges = edges.filter((e: any) => e.source === nodeId);
      for (const edge of nextEdges) {
        const hibernated = await this.traverseFromNode(
          edge.target,
          nodes,
          edges,
          payload,
          executionId,
          workflowId,
          tenantId,
          executionSessionId,
          depth,
          stepLogs,
        );
        if (hibernated) return true;
      }
    } else if (node.type === 'condition') {
      // Condition node: evaluate and follow True/False branch
      const conditionConfig = node.config as ConditionGroup | undefined;
      let matched = true;

      if (conditionConfig && conditionConfig.rules) {
        matched = this.conditionEvaluator.evaluate(
          conditionConfig,
          payload.data,
        );
      }

      const branch = matched ? 'matched' : 'not_matched';

      this.bufferStep(stepLogs, {
        nodeId,
        nodeName: node.config?.name || 'Condition',
        nodeType: 'condition',
        branch,
        status: 'success',
        input: { conditionConfig, recordData: payload.data },
        output: { matched, branch },
        startedAt: stepStart,
        completedAt: new Date(),
        duration: Date.now() - stepStart.getTime(),
      });

      // Follow edges matching the branch (True/False Split)
      const branchEdges = edges.filter((e: any) => {
        if (e.source !== nodeId) return false;
        // If edge has sourceHandle, match it; otherwise follow all
        if (e.sourceHandle) return e.sourceHandle === branch;
        return matched; // Legacy: only follow if matched
      });

      for (const edge of branchEdges) {
        const hibernated = await this.traverseFromNode(
          edge.target,
          nodes,
          edges,
          payload,
          executionId,
          workflowId,
          tenantId,
          executionSessionId,
          depth,
          stepLogs,
        );
        if (hibernated) return true;
      }
    } else if (node.type === 'action') {
      const actionConfig = await this.encryptActionConfigForQueue(
        node.config || {},
      );
      // Action node: dispatch to typed queue
      const actionData: AutomationActionJobData = {
        executionId,
        workflowId,
        tenantId,
        nodeId,
        nodeName: actionConfig?.name || actionConfig?.actionType || 'Action',
        actionType: actionConfig?.actionType,
        actionConfig,
        recordId: payload.recordId,
        recordType: payload.object,
        recordData: payload.data,
        automationDepth: depth,
        automationBreadcrumbs: this.appendBreadcrumb(
          payload.automationBreadcrumbs,
          workflowId,
        ),
        sourceWorkflowId: workflowId,
      };

      try {
        await this.actionProducer.dispatch(actionData);

        this.bufferStep(stepLogs, {
          nodeId,
          nodeName: actionData.nodeName,
          nodeType: 'action',
          status: 'success',
          input: { actionType: actionConfig?.actionType, config: actionConfig },
          output: { queued: true },
          startedAt: stepStart,
          completedAt: new Date(),
          duration: Date.now() - stepStart.getTime(),
        });
      } catch (error: any) {
        this.bufferStep(stepLogs, {
          nodeId,
          nodeName: actionData.nodeName,
          nodeType: 'action',
          status: 'failed',
          input: { actionType: node.config?.actionType },
          error: { code: 'ACTION_DISPATCH_FAILED', message: error.message },
          startedAt: stepStart,
          completedAt: new Date(),
          duration: Date.now() - stepStart.getTime(),
        });
        throw error;
      }

      // Follow edges from action to next nodes (chaining)
      const nextEdges = edges.filter((e: any) => e.source === nodeId);
      for (const edge of nextEdges) {
        const hibernated = await this.traverseFromNode(
          edge.target,
          nodes,
          edges,
          payload,
          executionId,
          workflowId,
          tenantId,
          executionSessionId,
          depth,
          stepLogs,
        );
        if (hibernated) return true;
      }
    } else if (node.type === 'wait') {
      // ΓöÇΓöÇ Wait/Delay node: hibernate execution ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      const config = node.config as WaitNodeConfig;
      const delayMs = this.computeDelayMs(config);

      this.logger.log(
        `[Orchestrator] ΓÅ╕ Wait node "${config.name || 'Wait'}": ` +
          `delay=${config.delayValue} ${config.delayUnit} (${delayMs}ms)`,
      );

      // Log the wait step
      this.bufferStep(stepLogs, {
        nodeId,
        nodeName: config.name || 'Wait',
        nodeType: 'wait' as any,
        status: 'waiting' as any,
        input: {
          delayType: config.delayType,
          delayValue: config.delayValue,
          delayUnit: config.delayUnit,
        },
        output: {
          delayMs,
          resumeAt: new Date(Date.now() + delayMs).toISOString(),
        },
        startedAt: stepStart,
        completedAt: new Date(),
        duration: 0,
      });
      await this.flushStepLogs(executionId, stepLogs);

      // Schedule delayed resume for each downstream edge
      const nextEdges = edges.filter((e: any) => e.source === nodeId);
      for (const edge of nextEdges) {
        const delayedData: AutomationDelayedJobData = {
          executionId,
          workflowId,
          tenantId,
          resumeFromNodeId: edge.target,
          recordId: payload.recordId,
          recordType: payload.object,
          automationDepth: depth,
          automationBreadcrumbs: this.appendBreadcrumb(
            payload.automationBreadcrumbs,
            workflowId,
          ),
          sourceWorkflowId: workflowId,
          executionSessionId,
        };

        await this.delayedProducer.scheduleResume(delayedData, delayMs);
      }

      // STOP traversal ΓÇö delayed queue will resume
      return true;
    }

    return false;
  }

  private bufferStep(stepLogs: ExecutionStep[], step: ExecutionStep): void {
    stepLogs.push(step);
  }

  private async flushStepLogs(
    executionId: string,
    stepLogs: ExecutionStep[],
  ): Promise<void> {
    if (stepLogs.length === 0) return;
    const batch = stepLogs.splice(0, stepLogs.length);
    await this.executionLogRepo.logSteps(executionId, batch);
  }

  private appendBreadcrumb(
    breadcrumbs: string[] | undefined,
    workflowId: string,
  ): string[] {
    return [...new Set([...(breadcrumbs ?? []), workflowId])];
  }

  /**
   * Compute delay in milliseconds from a WaitNodeConfig.
   */
  private computeDelayMs(config: WaitNodeConfig): number {
    const value = Math.max(1, config.delayValue || 1);

    switch (config.delayUnit) {
      case 'minutes':
        return value * 60 * 1000;
      case 'hours':
        return value * 60 * 60 * 1000;
      case 'days':
        return value * 24 * 60 * 60 * 1000;
      default:
        return value * 60 * 1000; // default to minutes
    }
  }

  private async encryptActionConfigForQueue(
    config: Record<string, any>,
  ): Promise<Record<string, any>> {
    if (config.actionType !== 'webhook') return config;
    return (await this.webhookHeaderCrypto.encryptWebhookConfig(config)).config;
  }
}

