import { Injectable, Logger } from '@nestjs/common';
import { OnEvent } from '@nestjs/event-emitter';
import { EventEmitter2 } from '@nestjs/event-emitter';

/**
 * OmniAutomationBridge ΓÇö bridges omni-channel events into the Automation Engine
 * by re-emitting them as `automation.*` events that the existing
 * AutomationEventListenerService can process.
 *
 * Supported mappings:
 *   - omni.conversation.created     ΓåÆ automation.record_created.Conversation
 *   - omni.conversation.status_changed ΓåÆ automation.field_updated.Conversation
 *   - omni.message.persisted        ΓåÆ automation.record_created.Message
 *
 * The Automation Engine already handles:
 *   - Workflow matching via WorkflowOrchestratorService
 *   - Condition evaluation
 *   - Action execution (email, SMS, webhook, update_field, route_to_team)
 *   - Loop prevention and bulk throttling
 *
 * This bridge simply translates omni events into the existing format.
 */
@Injectable()
export class OmniAutomationBridgeService {
  private readonly logger = new Logger(OmniAutomationBridgeService.name);

  constructor(private readonly eventEmitter: EventEmitter2) {}

  /**
   * When a new conversation is created, emit as automation record_created.
   */
  @OnEvent('omni.conversation.created')
  async onConversationCreated(payload: {
    tenantId: string;
    conversationId: string;
    channelType: string;
    senderId: string;
    conversation?: any;
  }): Promise<void> {
    if (!payload.tenantId || !payload.conversationId) return;

    const data = payload.conversation ?? {
      id: payload.conversationId,
      channelType: payload.channelType,
      senderId: payload.senderId,
    };

    this.logger.log(
      `[OmniAutoBridge] conversation.created ΓåÆ automation.record_created.Conversation ` +
        `(tenant=${payload.tenantId}, conv=${payload.conversationId})`,
    );

    this.eventEmitter.emit('automation.record_created.Conversation', {
      tenantId: payload.tenantId,
      event: 'record_created',
      object: 'Conversation',
      recordId: payload.conversationId,
      data: {
        id: payload.conversationId,
        channelType: data.channelType,
        senderId: payload.senderId,
        customerName: data.customer?.name ?? payload.senderId,
        customerEmail: data.customer?.email ?? null,
        customerPhone: data.customer?.phone ?? null,
        status: data.status ?? 'open',
        contactId: data.contactId ?? null,
        ...data,
      },
      automationDepth: 0,
    });
  }

  /**
   * When a conversation's status changes (open ΓåÆ resolved, etc.),
   * emit as automation field_updated.
   */
  @OnEvent('omni.conversation.status_changed')
  async onConversationStatusChanged(payload: {
    tenantId: string;
    conversationId: string;
    status: string;
    oldStatus: string;
    agentId: string | null;
    reason?: string;
    channelType?: string;
  }): Promise<void> {
    if (!payload.tenantId || !payload.conversationId) return;

    this.logger.log(
      `[OmniAutoBridge] conversation.status_changed ΓåÆ automation.field_updated.Conversation ` +
        `(tenant=${payload.tenantId}, conv=${payload.conversationId}, ${payload.oldStatus} ΓåÆ ${payload.status})`,
    );

    this.eventEmitter.emit('automation.field_updated.Conversation', {
      tenantId: payload.tenantId,
      event: 'field_updated',
      object: 'Conversation',
      recordId: payload.conversationId,
      data: {
        id: payload.conversationId,
        status: payload.status,
        channelType: payload.channelType,
        assignedAgentId: payload.agentId,
        resolveReason: payload.reason,
      },
      changedFields: ['status'],
      automationDepth: 0,
    });
  }

  /**
   * When an inbound message is persisted, emit as automation record_created.Message.
   * This enables keyword-based triggers (e.g. "if message contains 'urgent' ΓåÆ create ticket").
   */
  @OnEvent('omni.message.persisted')
  async onMessagePersisted(payload: {
    tenantId: string;
    conversationId: string;
    messageId?: string;
    internalMessageId?: string;
    content?: string;
    messageType?: string;
    senderType?: string;
    senderId?: string;
    channelType?: string;
  }): Promise<void> {
    if (!payload.tenantId || !payload.conversationId) return;

    // Only trigger automations for customer messages (not agent replies)
    if (payload.senderType && payload.senderType !== 'customer') return;

    const messageId =
      payload.internalMessageId ?? payload.messageId ?? 'unknown';

    this.logger.log(
      `[OmniAutoBridge] message.persisted ΓåÆ automation.record_created.Message ` +
        `(tenant=${payload.tenantId}, msg=${messageId})`,
    );

    this.eventEmitter.emit('automation.record_created.Message', {
      tenantId: payload.tenantId,
      event: 'record_created',
      object: 'Message',
      recordId: messageId,
      data: {
        id: messageId,
        conversationId: payload.conversationId,
        content: payload.content ?? '',
        messageType: payload.messageType ?? 'text',
        senderType: payload.senderType ?? 'customer',
        senderId: payload.senderId,
        channelType: payload.channelType,
      },
      automationDepth: 0,
    });
  }
}

import { Processor, OnWorkerEvent } from '@nestjs/bullmq';
import { Job } from 'bullmq';
import { Logger } from '@nestjs/common';
import { ClsService } from 'nestjs-cls';
import {
  BaseTenantConsumer,
  TenantJobData,
} from '../../queue/base-tenant.consumer';
import {
  AUTOMATION_ACTION_QUEUE,
  AUTOMATION_EMAIL_QUEUE,
  AUTOMATION_SMS_QUEUE,
  AUTOMATION_INTERNAL_QUEUE,
  AUTOMATION_WEBHOOK_QUEUE,
  AutomationActionJobData,
} from './automation-queue.constants';
import {
  ActionExecutor,
  ActionExecutionResult,
  SendEmailExecutor,
  SendSmsExecutor,
  UpdateFieldExecutor,
  RouteToTeamExecutor,
  WebhookExecutor,
} from '../engine/action-executors';
import { AutomationExecutionLogRepository } from '../infrastructure/persistence/document/repositories/automation-execution-log.repository';
import { AutomationDlqProducer } from './automation-dlq.producer';

/**
 * Shared action processing logic used by all typed queue processors.
 * Extracted to avoid code duplication across 4+ queue consumers.
 *
 * NOTE: CLS tenant context is now set by BaseTenantConsumer.process() ΓÇö
 * this mixin no longer wraps with runWithTenantContext.
 */
export class ActionProcessorMixin {
  constructor(
    protected readonly executors: Map<string, ActionExecutor>,
    protected readonly executionLogRepo: AutomationExecutionLogRepository,
    protected readonly dlqProducer: AutomationDlqProducer,
    protected readonly logger: Logger,
  ) {}

  async processAction(job: Job<AutomationActionJobData>): Promise<void> {
    const data = job.data;
    const validationError = this.validateJobData(data);

    if (validationError) {
      const reason = `schema-invalid: ${validationError}`;
      this.logger.error(`[Processor] Job ${job.id} rejected: ${reason}`);
      await this.dlqProducer
        .sendToDlq(data as AutomationActionJobData, reason)
        .catch((dlqErr) =>
          this.logger.error(
            `[Processor] Failed to send invalid job ${job.id} to DLQ: ${dlqErr.message}`,
          ),
        );
      return;
    }

    // CLS tenant context is already set by BaseTenantConsumer.process()
    return this.processActionInTenantContext(job);
  }

  private validateJobData(data: unknown): string | null {
    if (!this.isRecord(data)) {
      return 'payload must be an object';
    }

    const requiredStringFields = [
      'executionId',
      'workflowId',
      'tenantId',
      'nodeId',
      'nodeName',
      'actionType',
      'recordId',
      'recordType',
      'sourceWorkflowId',
    ];

    for (const field of requiredStringFields) {
      if (typeof data[field] !== 'string' || data[field].trim().length === 0) {
        return `${field} is required`;
      }
    }

    if (!/^[0-9a-fA-F]{24}$/.test(data.tenantId as string)) {
      return `tenantId must be a Mongo ObjectId, got "${data.tenantId}"`;
    }

    const validActions = new Set([
      'send_email',
      'send_sms',
      'update_field',
      'route_to_team',
      'webhook',
    ]);
    if (!validActions.has(data.actionType as string)) {
      return `unknown actionType "${data.actionType}"`;
    }

    const validRecordTypes = new Set([
      'Lead',
      'Contact',
      'Ticket',
      'Deal',
      'Account',
      'Task',
    ]);
    if (!validRecordTypes.has(data.recordType as string)) {
      return `unknown recordType "${data.recordType}"`;
    }

    if (!this.isRecord(data.actionConfig)) {
      return 'actionConfig must be an object';
    }

    if (!this.isRecord(data.recordData)) {
      return 'recordData must be an object';
    }

    if (
      typeof data.automationDepth !== 'number' ||
      !Number.isInteger(data.automationDepth) ||
      data.automationDepth < 0
    ) {
      return 'automationDepth must be a non-negative integer';
    }

    if (
      data.automationBreadcrumbs !== undefined &&
      (!Array.isArray(data.automationBreadcrumbs) ||
        data.automationBreadcrumbs.some((item) => typeof item !== 'string'))
    ) {
      return 'automationBreadcrumbs must be an array of strings';
    }

    return null;
  }

  private isRecord(value: unknown): value is Record<string, any> {
    return typeof value === 'object' && value !== null && !Array.isArray(value);
  }

  private async processActionInTenantContext(
    job: Job<AutomationActionJobData>,
  ): Promise<void> {
    const data = job.data;
    const stepStart = new Date();

    this.logger.log(
      `[Processor] Job ${job.id} | action=${data.actionType} workflow=${data.workflowId} node=${data.nodeId}`,
    );

    const executor = this.executors.get(data.actionType);

    if (!executor) {
      const errorMsg = `Unknown action type: ${data.actionType}`;
      this.logger.error(`[Processor] ${errorMsg}`);

      await this.logActionStep(data, stepStart, {
        success: false,
        error: { code: 'UNKNOWN_ACTION_TYPE', message: errorMsg },
      });

      throw new Error(errorMsg);
    }

    try {
      const result = await executor.execute(data);

      await this.logActionStep(data, stepStart, result);

      if (!result.success) {
        // ΓöÇΓöÇ Smart Retry (Phase 2): Non-retryable ΓåÆ DLQ immediately ΓöÇΓöÇΓöÇΓöÇ
        if (result.retryable === false) {
          this.logger.warn(
            `[Processor] Non-retryable failure for node=${data.nodeId}: ${result.error?.code} ΓÇö routing to DLQ (skip BullMQ retry)`,
          );
          await this.dlqProducer
            .sendToDlq(data, result.error?.message || 'Non-retryable failure')
            .catch((dlqErr) =>
              this.logger.error(
                `[Processor] Failed to send to DLQ: ${dlqErr.message}`,
              ),
            );
          // Return without throwing ΓÇö prevents BullMQ from retrying
          return;
        }

        this.logger.warn(
          `[Processor] Action ${data.actionType} failed for node=${data.nodeId}: ${result.error?.message}`,
        );
        throw new Error(result.error?.message || 'Action execution failed');
      }

      this.logger.log(
        `[Processor] Γ£à Action ${data.actionType} completed for node=${data.nodeId}`,
      );
    } catch (error: any) {
      // Log if not already logged
      if (!error.message?.startsWith('Action execution failed')) {
        await this.logActionStep(data, stepStart, {
          success: false,
          error: { code: 'EXECUTOR_EXCEPTION', message: error.message },
        });
      }

      throw error; // Re-throw for BullMQ retry
    }
  }

  handleFailedJob(job: Job, error: Error): void {
    const attemptsRemaining = (job.opts?.attempts ?? 3) - job.attemptsMade;

    if (attemptsRemaining <= 0) {
      this.logger.warn(
        `[Processor] Job ${job.id} exhausted all retries ΓÇö routing to DLQ`,
      );
      this.dlqProducer
        .sendToDlq(job.data, error.message)
        .catch((dlqErr) =>
          this.logger.error(
            `[Processor] Failed to send to DLQ: ${dlqErr.message}`,
          ),
        );
    } else {
      this.logger.error(
        `Job ${job.id} failed (${attemptsRemaining} retries left). Name: ${job.name}. Error: ${error.message}`,
      );
    }
  }

  private async logActionStep(
    data: AutomationActionJobData,
    stepStart: Date,
    result: ActionExecutionResult,
  ): Promise<void> {
    try {
      await this.executionLogRepo.logStep(data.executionId, {
        nodeId: data.nodeId,
        nodeName: data.nodeName,
        nodeType: 'action',
        status: result.success ? 'success' : 'failed',
        input: {
          actionType: data.actionType,
          recordId: data.recordId,
          recordType: data.recordType,
        },
        output: result.output,
        error: result.error
          ? { code: result.error.code, message: result.error.message }
          : undefined,
        startedAt: stepStart,
        completedAt: new Date(),
        duration: Date.now() - stepStart.getTime(),
      });
    } catch (logError: any) {
      this.logger.error(
        `[Processor] Failed to log step for execution=${data.executionId}: ${logError.message}`,
      );
    }
  }
}

