import { OnWorkerEvent, Processor } from '@nestjs/bullmq';
import { Job } from 'bullmq';
import { Logger } from '@nestjs/common';
import { ClsService } from 'nestjs-cls';
import {
  BaseTenantConsumer,
  TenantJobData,
} from '../../queue/base-tenant.consumer';
import {
  AUTOMATION_DELAYED_QUEUE,
  AutomationDelayedJobData,
  AutomationDelayedQueueJobData,
} from './automation-queue.constants';
import { WorkflowOrchestratorService } from '../engine/workflow-orchestrator.service';
import { CrmRecordUpdateService } from '../engine/crm-record-update.service';
import { AutomationExecutionLogRepository } from '../infrastructure/persistence/document/repositories/automation-execution-log.repository';
import { AutomationWorkflowRepository } from '../infrastructure/persistence/document/repositories/automation-workflow.repository';
import { AutomationDelayedJobRepository } from '../infrastructure/persistence/document/repositories/automation-delayed-job.repository';
import { runWithTenantContext } from '../../common/tenancy/tenant-context';

/**
 * Consumes hot resume jobs from Redis. The source of truth is MongoDB when
 * delayedJobId is present; payload-only jobs are supported for pre-migration
 * BullMQ delayed jobs that may still exist in Redis.
 */
@Processor(AUTOMATION_DELAYED_QUEUE)
export class AutomationDelayedProcessor extends BaseTenantConsumer<AutomationDelayedQueueJobData> {
  protected readonly logger = new Logger(AutomationDelayedProcessor.name);
  protected readonly cls: ClsService;

  constructor(
    private readonly orchestrator: WorkflowOrchestratorService,
    private readonly crmUpdate: CrmRecordUpdateService,
    private readonly executionLogRepo: AutomationExecutionLogRepository,
    private readonly workflowRepo: AutomationWorkflowRepository,
    private readonly delayedJobRepo: AutomationDelayedJobRepository,
    cls: ClsService,
  ) {
    super();
    this.cls = cls;
  }

  protected async handle(
    job: Job<AutomationDelayedQueueJobData>,
  ): Promise<void> {
    const data = await this.resolveJobData(job.data);
    if (!data) return;

    try {
      // Audit trail: mark as automation flow execution
      this.cls.set('executionSource', 'A_F');
      this.cls.set('sourceContext', { flowId: data.workflowId });

      await this.resumeWorkflow(data);

      if (job.data.delayedJobId) {
        await this.delayedJobRepo.markCompleted(job.data.delayedJobId);
      }
    } catch (error: any) {
      this.logger.error(
        `[DelayedResume] Failed execution=${data.executionId}: ${error.message}`,
        error.stack,
      );
      throw error;
    }
  }

  /**
   * onFailed override: uses runWithTenantContext because this runs
   * OUTSIDE the process() CLS context (BullMQ event callback).
   */
  @OnWorkerEvent('failed')
  override async onFailed(
    job: Job<AutomationDelayedQueueJobData>,
    error: Error,
  ) {
    await super.onFailed(job, error);

    const attemptsRemaining = (job.opts?.attempts ?? 1) - job.attemptsMade;
    if (attemptsRemaining > 0 || !job.data.delayedJobId) return;

    const delayedJobId = job.data.delayedJobId;
    runWithTenantContext(this.cls, job.data.tenantId, () => {
      this.delayedJobRepo
        .markFailed(delayedJobId, error.message)
        .catch((repoError) =>
          this.logger.error(
            `[DelayedResume] Failed to mark delayed job as failed: ${repoError.message}`,
            repoError.stack,
          ),
        );
    });
  }

  private async resolveJobData(
    hotData: AutomationDelayedQueueJobData,
  ): Promise<AutomationDelayedJobData | null> {
    if (!hotData.delayedJobId) return hotData;

    const delayedJob = await this.delayedJobRepo.markProcessing(
      hotData.delayedJobId,
    );

    if (!delayedJob) {
      this.logger.warn(
        `[DelayedResume] Skipping hot job ${hotData.delayedJobId}; ` +
          'it is already terminal or not ready for processing',
      );
      return null;
    }

    return delayedJob.payload;
  }

  private async resumeWorkflow(data: AutomationDelayedJobData): Promise<void> {
    this.logger.log(
      `[DelayedResume] Resuming execution=${data.executionId} ` +
        `workflow=${data.workflowId} node=${data.resumeFromNodeId} ` +
        `record=${data.recordType}(${data.recordId})`,
    );

    const record = await this.crmUpdate.fetchRecord(
      data.recordType,
      data.recordId,
    );

    if (!record) {
      this.logger.warn(
        `[DelayedResume] Record ${data.recordType}(${data.recordId}) not found; ` +
          'it may have been deleted during the wait period',
      );

      const stepStart = new Date();
      await this.executionLogRepo.logStep(data.executionId, {
        nodeId: data.resumeFromNodeId,
        nodeName: 'Resume (after wait)',
        nodeType: 'action',
        status: 'failed',
        input: { resumeFromNodeId: data.resumeFromNodeId },
        error: {
          code: 'RECORD_NOT_FOUND',
          message: `Record ${data.recordType}(${data.recordId}) was deleted during wait period`,
        },
        startedAt: stepStart,
        completedAt: new Date(),
        duration: 0,
      });

      await this.executionLogRepo.failExecution(data.executionId, {
        code: 'RECORD_NOT_FOUND',
        message: 'Record deleted during delay; cannot resume workflow',
        nodeId: data.resumeFromNodeId,
      });

      throw new Error(
        `RECORD_NOT_FOUND: ${data.recordType}(${data.recordId}) deleted during wait`,
      );
    }

    const workflow = await this.workflowRepo.findById(
      data.tenantId,
      data.workflowId,
    );

    if (!workflow) {
      this.logger.error(
        `[DelayedResume] Workflow ${data.workflowId} not found; cannot resume`,
      );
      await this.executionLogRepo.failExecution(data.executionId, {
        code: 'WORKFLOW_NOT_FOUND',
        message: `Workflow ${data.workflowId} was deleted during delay; cannot resume`,
      });
      throw new Error(`WORKFLOW_NOT_FOUND: ${data.workflowId}`);
    }

    const publishedNodes = (workflow as any).publishedNodes || [];
    const publishedEdges = (workflow as any).publishedEdges || [];

    if (publishedNodes.length === 0) {
      this.logger.warn(
        `[DelayedResume] Workflow ${data.workflowId} has no published nodes`,
      );
      await this.executionLogRepo.failExecution(data.executionId, {
        code: 'UNPUBLISHED_WORKFLOW',
        message: 'Workflow was unpublished during delay period',
      });
      throw new Error(`UNPUBLISHED_WORKFLOW: ${data.workflowId}`);
    }

    await this.orchestrator.resumeFromNode(
      data.resumeFromNodeId,
      publishedNodes,
      publishedEdges,
      {
        tenantId: data.tenantId,
        event: 'record_created',
        object: data.recordType,
        recordId: data.recordId,
        data: record,
        automationDepth: data.automationDepth,
        automationBreadcrumbs: data.automationBreadcrumbs,
        _automationSourceWorkflowId: data.sourceWorkflowId,
      },
      data.executionId,
      data.workflowId,
      data.tenantId,
      data.executionSessionId,
      data.automationDepth,
    );

    this.logger.log(
      `[DelayedResume] Resumed and completed execution=${data.executionId}`,
    );
  }
}

import {
  Controller,
  Post,
  Body,
  Logger,
  BadRequestException,
  NotFoundException,
} from '@nestjs/common';
import { ApiTags, ApiOperation, ApiBearerAuth } from '@nestjs/swagger';
import { ClsService } from 'nestjs-cls';
import { TransportPoolService } from '../transport-pool.service';
import { InjectModel } from '@nestjs/mongoose';
import { Model, Types } from 'mongoose';
import { EmailContentSchemaClass } from '../infrastructure/persistence/document/entities/email-content.schema';
import { EmailMetadataSchemaClass } from '../infrastructure/persistence/document/entities/email-metadata.schema';
import { OutboundQueueService } from '../services/outbound-queue.service';
import nodemailer from 'nodemailer';

class SendEmailDto {
  configId: string;
  to: string[];
  cc?: string[];
  bcc?: string[];
  subject: string;
  htmlBody: string;
  contactId?: string;
}

/**
 * EmailSendController ΓÇö Standalone email send endpoint.
 *
 * This controller enables sending emails **without** an omni conversationId.
 * It resolves SMTP credentials directly from configId via TransportPool,
 * following the same pattern as SendEmailExecutor in automation rules.
 *
 * When the email syncs back via IMAP, the system will auto-create
 * an omni conversation through the existing pipeline:
 *   ImapPoller ΓåÆ EmailInboundListener ΓåÆ ConversationService
 */
@ApiTags('Email Send')
@ApiBearerAuth()
@Controller({ path: 'channels', version: '1' })
export class EmailSendController {
  private readonly logger = new Logger(EmailSendController.name);

  constructor(
    private readonly cls: ClsService,
    private readonly transportPool: TransportPoolService,
    private readonly outboundQueue: OutboundQueueService,
    @InjectModel(EmailContentSchemaClass.name)
    private readonly emailContentModel: Model<EmailContentSchemaClass>,
    @InjectModel(EmailMetadataSchemaClass.name)
    private readonly emailMetadataModel: Model<EmailMetadataSchemaClass>,
  ) {}

  @Post('email/send')
  @ApiOperation({ summary: 'Send standalone email (no conversation required)' })
  async sendEmail(@Body() dto: SendEmailDto) {
    const tenantId = this.cls.get('tenantId');
    const agentId = this.cls.get('userId') || 'system';

    if (!tenantId) {
      throw new BadRequestException('Missing tenant context');
    }
    if (!dto.configId || !dto.to?.length || !dto.subject) {
      throw new BadRequestException('configId, to, and subject are required');
    }

    // 1. Resolve SMTP transport by configId (same as SendEmailExecutor)
    const transportConfig = await this.transportPool.resolveWithTenantGuard(
      dto.configId,
      tenantId,
    );

    if (!transportConfig || transportConfig.providerType !== 'smtp') {
      throw new NotFoundException(
        'Invalid or missing SMTP configuration for this channel',
      );
    }

    const { user, password } = transportConfig.credentials;
    const { host, port, fromEmail, fromName } = transportConfig.publicSettings;
    const numPort = Number(port);

    // 2. Throttle check
    const recipients = [
      ...(dto.to || []),
      ...(dto.cc || []),
      ...(dto.bcc || []),
    ];
    const throttleResult = await this.outboundQueue.checkSendAllowed(
      tenantId,
      dto.configId,
      host,
      recipients.length,
    );
    if (!throttleResult.allowed) {
      throw new BadRequestException(
        throttleResult.reason || 'Send rate limited',
      );
    }

    // 3. Create Nodemailer transporter
    const transporter = nodemailer.createTransport({
      host,
      port: numPort,
      secure: numPort === 465,
      auth: { user, pass: password },
      tls: { rejectUnauthorized: process.env.NODE_ENV === 'production' },
    });

    // 4. Build and send email
    const from = `"${fromName || 'CRM'}" <${fromEmail || user}>`;
    const generatedMessageId = new Types.ObjectId();

    try {
      const result = await transporter.sendMail({
        from,
        to: dto.to,
        cc: dto.cc || [],
        bcc: dto.bcc || [],
        subject: dto.subject,
        html: dto.htmlBody,
        messageId: `<${generatedMessageId}@crm.local>`,
      });

      this.logger.log(
        `[EmailSend] Γ£à Sent to=${dto.to.join(',')} subject="${dto.subject}" messageId=${result.messageId}`,
      );

      // 5. Persist to email_contents for tracking (searchable)
      await this.emailContentModel.create({
        tenantId,
        messageId: generatedMessageId,
        contactIds: dto.contactId ? [dto.contactId] : [],
        subject: dto.subject,
        htmlBody: dto.htmlBody || '',
        textBody: '',
        attachments: [],
        from: fromEmail || user,
        to: dto.to,
        cc: dto.cc || [],
        rfc822MessageId: result.messageId || null,
      });

      // 6. Persist metadata for thread tracking
      await this.emailMetadataModel.create({
        tenantId,
        mailboxId: dto.configId,
        messageId: generatedMessageId,
        emailMessageId: result.messageId || `<${generatedMessageId}@crm.local>`,
        from: fromEmail || user,
        to: dto.to,
        cc: dto.cc || [],
        bcc: dto.bcc || [],
        crmFolder: 'sent',
        deliveryStatus: 'sent',
      });

      return {
        ok: true,
        messageId: result.messageId,
        generatedMessageId: generatedMessageId.toString(),
      };
    } catch (error: any) {
      this.logger.error(`[EmailSend] Γ¥î Failed: ${error.message}`, error.stack);
      throw new BadRequestException(`Failed to send email: ${error.message}`);
    }
  }
}

import { Injectable, Logger, OnModuleDestroy } from '@nestjs/common';
import { EventEmitter2 } from '@nestjs/event-emitter';
import { InjectModel } from '@nestjs/mongoose';
import { Model, Types } from 'mongoose';
import { RedisLockService } from '../../redis/redis-lock.service';
import { RedisService } from '../../redis/redis.service';
import { BusinessHoursService } from '../../omni-inbound/services/business-hours.service';
import { EmailNormalizerService } from './email-normalizer.service';
import { ChannelConfigRepository } from '../infrastructure/persistence/document/repositories/channel-config.repository';
import { EmailContentSchemaClass } from '../infrastructure/persistence/document/entities/email-content.schema';
import { EmailMetadataSchemaClass } from '../infrastructure/persistence/document/entities/email-metadata.schema';
import { OmniMessageSchemaClass } from '../../omni-inbound/infrastructure/persistence/document/entities/omni-message.schema';
import { ICryptoService, CRYPTO_SERVICE_TOKEN } from '../domain/crypto.service';
import { EmailChannelSettingsService } from './email-channel-settings.service';
import { Inject } from '@nestjs/common';
import { simpleParser, ParsedMail } from 'mailparser';
import { OAuth2TokenManager } from './oauth2-token-manager.service';
import { ClsService } from 'nestjs-cls';
import { runWithTenantContext } from '../../common/tenancy/tenant-context';
import {
  isEmailWorkerRuntime,
  isWorkerRuntime,
} from '../../config/runtime-role';

type MailboxLabelContext = {
  crmFolder: string | null;
  providerFolder: string | null;
  providerLabelIds: string[];
  providerLabels: string[];
};

type ProviderLabelDetail = {
  id: string;
  name: string;
  type: 'system' | 'user';
  color: string | null;
};

/**
 * ImapPollerService ΓÇö Enterprise email inbound engine.
 *
 * Architecture:
 *   - Scheduled via setInterval (not BullMQ cron, to support dynamic intervals)
 *   - Each tenant's SMTP config with IMAP fields triggers a polling job
 *   - Distributed Redis Lock prevents double-polling in multi-instance deploy
 *   - Dynamic Polling: Business-Hour-aware interval (2min active / 15min idle/off-hours)
 *   - Timezone-aware: reads tenant's Business Hours config, NOT hardcoded (GCC support)
 *
 * Flow:
 *   1. Scan all tenant SMTP configs with imapHost configured
 *   2. For each config: acquire Redis lock ΓåÆ connect IMAP ΓåÆ fetch UNSEEN ΓåÆ process
 *   3. EmailNormalizer filters auto-responders & bounces
 *   4. Clean emails ΓåÆ save to email_contents/email_metadata ΓåÆ emit to OmniInbound pipeline
 */
@Injectable()
export class ImapPollerService implements OnModuleDestroy {
  private readonly logger = new Logger(ImapPollerService.name);
  private pollTimer: NodeJS.Timeout | null = null;
  /** Graceful shutdown flag ΓÇö stops in-flight polling loops */
  private destroying = false;
  /**
   * Track in-flight poll promises so onModuleDestroy can wait for active
   * IMAP sessions to drain before the process exits. Without this, SIGTERM
   * during a poll leaves the mailbox lock held in Redis for LOCK_TTL_MS.
   */
  private readonly inFlightPolls = new Set<Promise<unknown>>();

  /** Active interval (within business hours + recent activity) */
  private readonly ACTIVE_INTERVAL_MS = 2 * 60 * 1000; // 2 minutes
  /** Idle interval (outside business hours or no recent activity) */
  private readonly IDLE_INTERVAL_MS = 5 * 60 * 1000; // 5 minutes
  /** Lock TTL: max time a single poll can take before lock expires */
  private readonly LOCK_TTL_MS = 5 * 60 * 1000; // 5 minutes (handles large batches)
  /** Max emails to process per poll cycle (rest will be caught next cycle) */
  private readonly MAX_BATCH_SIZE = 10;
  /** Hard cap for raw RFC822 parsing until attachment streaming is implemented. */
  private readonly MAX_RAW_EMAIL_BYTES = 15 * 1024 * 1024;
  /** Activity threshold: tenant is "idle" if no email in/out for 24h */
  private readonly ACTIVITY_THRESHOLD_MS = 24 * 60 * 60 * 1000;

  constructor(
    private readonly configRepo: ChannelConfigRepository,
    private readonly lockService: RedisLockService,
    private readonly redisService: RedisService,
    private readonly businessHoursService: BusinessHoursService,
    private readonly normalizer: EmailNormalizerService,
    private readonly emailSettings: EmailChannelSettingsService,
    private readonly oauth2TokenManager: OAuth2TokenManager,
    private readonly cls: ClsService,
    private readonly eventEmitter: EventEmitter2,
    @Inject(CRYPTO_SERVICE_TOKEN)
    private readonly crypto: ICryptoService,
    @InjectModel(EmailContentSchemaClass.name)
    private readonly emailContentModel: Model<EmailContentSchemaClass>,
    @InjectModel(EmailMetadataSchemaClass.name)
    private readonly emailMetadataModel: Model<EmailMetadataSchemaClass>,
    @InjectModel(OmniMessageSchemaClass.name)
    private readonly omniMessageModel: Model<OmniMessageSchemaClass>,
  ) {
    // Only start IMAP polling in email-worker (or legacy monolith worker) process.
    // Prevents duplicate polling from api-service and omni-worker-service.
    if (isEmailWorkerRuntime() || isWorkerRuntime()) {
      void this.cleanupStaleLocks();
      this.startScheduler();
    } else {
      this.logger.log('[ImapPoller] Skipped ΓÇö not an email-worker process');
    }
  }

  async onModuleDestroy(): Promise<void> {
    this.destroying = true;
    if (this.pollTimer) {
      clearInterval(this.pollTimer);
      this.pollTimer = null;
    }

    if (this.inFlightPolls.size > 0) {
      this.logger.log(
        `[ImapPoller] Waiting for ${this.inFlightPolls.size} in-flight poll(s) to finishΓÇª`,
      );
      // Cap the drain to 25s so k8s SIGKILL doesn't overlap.
      await Promise.race([
        Promise.allSettled(Array.from(this.inFlightPolls)),
        new Promise((resolve) => setTimeout(resolve, 25_000).unref()),
      ]);
    }

    this.logger.log('[ImapPoller] Destroyed ΓÇö scheduler stopped');
  }

  /**
   * Wrap a poll task so it auto-registers / deregisters in inFlightPolls.
   * Use this around any async work that should be drained on shutdown.
   */
  private track<T>(task: Promise<T>): Promise<T> {
    this.inFlightPolls.add(task);
    task.finally(() => this.inFlightPolls.delete(task));
    return task;
  }

  // ΓöÇΓöÇ Stale Lock Cleanup (hot-reload / crash recovery) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  /**
   * On startup, delete any IMAP locks left by a previous process.
   * Since we're a fresh instance, no in-flight polls exist from THIS process.
   */
  private async cleanupStaleLocks(): Promise<void> {
    try {
      const client = this.redisService.getClient();
      let cursor = '0';
      let totalCleaned = 0;

      // Use SCAN instead of KEYS to avoid blocking the Redis event loop.
      // SCAN is O(1) per iteration and safe for production use.
      do {
        const reply = await client.scan(
          cursor,
          'MATCH',
          'imap:lock:*',
          'COUNT',
          100,
        );
        cursor = reply[0];
        const keys = reply[1];
        if (keys.length > 0) {
          await client.del(...keys);
          totalCleaned += keys.length;
        }
      } while (cursor !== '0');

      if (totalCleaned > 0) {
        this.logger.warn(
          `[ImapPoller] Cleaned up ${totalCleaned} stale lock(s) from previous instance`,
        );
      }
    } catch (err: any) {
      this.logger.error(
        `[ImapPoller] Failed to cleanup stale locks: ${err.message}`,
      );
    }
  }

  // ΓöÇΓöÇ Master Scheduler ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  /**
   * Master tick: runs every minute, decides which tenants need polling.
   * This is NOT a per-tenant timer ΓÇö it's a single scheduler that fans out.
   */
  private startScheduler(): void {
    // Run first tick after 30 seconds (let app bootstrap complete)
    setTimeout(() => this.masterTick(), 30_000);
    // Then every 60 seconds
    this.pollTimer = setInterval(() => this.masterTick(), 60_000);
    this.logger.log('[ImapPoller] Master scheduler started (60s tick)');
  }

  /**
   * Master tick: find all SMTP configs with IMAP enabled, check intervals.
   */
  private async masterTick(): Promise<void> {
    if (this.destroying) return;

    try {
      const imapConfigs = await this.findImapEnabledConfigs();

      if (imapConfigs.length === 0) {
        this.logger.log('[ImapPoller] Tick: No IMAP-enabled configs found');
        return;
      }

      this.logger.log(
        `[ImapPoller] Tick: ${imapConfigs.length} IMAP-enabled configs found`,
      );

      // Fan out: check each config's polling schedule
      await Promise.allSettled(
        imapConfigs.map((config) => this.checkAndPoll(config)),
      );
    } catch (err: any) {
      this.logger.error(`[ImapPoller] Master tick error: ${err.message}`);
    }
  }

  // ΓöÇΓöÇ Per-Tenant Polling Decision ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  /**
   * Decide whether to poll this tenant's mailbox NOW.
   * Uses Redis to track last poll time and compare with dynamic interval.
   */
  private async checkAndPoll(config: any): Promise<void> {
    const cacheKey = `imap:lastpoll:${config.id}`;
    const client = this.redisService.getClient();

    // Check when we last polled this config
    const lastPollStr = await client.get(cacheKey);
    const lastPollMs = lastPollStr ? parseInt(lastPollStr, 10) : 0;

    // Determine interval based on business hours + activity
    const interval = await runWithTenantContext(this.cls, config.tenantId, () =>
      this.getDynamicInterval(config.tenantId),
    );

    // First poll ever for this config ΓåÆ run immediately; otherwise respect interval
    if (lastPollMs > 0) {
      const elapsed = Date.now() - lastPollMs;

      if (elapsed < interval) {
        this.logger.log(
          `[ImapPoller] ${config.name}: Skipping ΓÇö next poll in ${Math.ceil((interval - elapsed) / 1000)}s`,
        );
        return;
      }
      this.logger.log(
        `[ImapPoller] ${config.name}: Interval elapsed (${Math.ceil(elapsed / 1000)}s >= ${Math.ceil(interval / 1000)}s) ΓÇö polling now`,
      );
    } else {
      this.logger.log(
        `[ImapPoller] ${config.name}: First poll ΓÇö running immediately`,
      );
    }

    // Time to poll ΓÇö acquire distributed lock
    const lockKey = `imap:lock:${config.id}`;

    try {
      await this.lockService.acquire(
        lockKey,
        this.LOCK_TTL_MS,
        async () => {
          this.logger.log(
            `[ImapPoller] ${config.name}: Lock acquired ΓÇö starting pollMailbox`,
          );
          await this.track(
            runWithTenantContext(this.cls, config.tenantId, () =>
              this.pollMailbox(config),
            ),
          );
          // Record poll time
          await client.set(cacheKey, Date.now().toString(), 'PX', interval * 2);
          this.logger.log(
            `[ImapPoller] ${config.name}: Poll complete ΓÇö recorded lastPoll`,
          );
        },
        200, // retry delay
        3, // max retries (don't fight for locks)
      );
    } catch (err: any) {
      // Lock busy = another instance is polling this mailbox.
      if (err.message?.includes('Could not acquire lock')) {
        this.logger.warn(
          `[ImapPoller] ${config.name}: Could not acquire lock ΓÇö another instance is polling`,
        );
        return;
      }
      this.logger.error(
        `[ImapPoller] Poll error for config ${config.name}: ${err.message}`,
      );
    }
  }

  /**
   * Dynamic Polling Interval ΓÇö Timezone-aware, Business-Hours-aware.
   *
   * Strategy (from Product Researcher feedback):
   *   - Within business hours + active (email in last 24h): 2 minutes
   *   - Within business hours + idle: 15 minutes
   *   - Outside business hours: 15 minutes
   *   - Uses tenant's configured timezone (GCC/Saudi support)
   */
  private async getDynamicInterval(tenantId: string): Promise<number> {
    // Dev mode: always poll at active interval (skip business-hours check)
    if (process.env.NODE_ENV !== 'production') {
      return this.ACTIVE_INTERVAL_MS;
    }

    try {
      // Check business hours (uses tenant's timezone, NOT hardcoded)
      const isBusinessHours =
        await this.businessHoursService.isWithinBusinessHours(tenantId);

      if (!isBusinessHours) {
        return this.IDLE_INTERVAL_MS;
      }

      // Check recent activity
      const activityKey = `imap:activity:${tenantId}`;
      const client = this.redisService.getClient();
      const lastActivity = await client.get(activityKey);

      if (lastActivity) {
        const elapsed = Date.now() - parseInt(lastActivity, 10);
        if (elapsed < this.ACTIVITY_THRESHOLD_MS) {
          return this.ACTIVE_INTERVAL_MS; // Active tenant
        }
      }

      return this.IDLE_INTERVAL_MS; // Idle tenant
    } catch {
      return this.IDLE_INTERVAL_MS; // Default to idle on error
    }
  }

  /**
   * Record activity for a tenant (called when email is received or sent).
   * Resets the idle timer so polling stays at 2-minute intervals.
   */
  async recordActivity(tenantId: string): Promise<void> {
    const client = this.redisService.getClient();
    await client.set(
      `imap:activity:${tenantId}`,
      Date.now().toString(),
      'PX',
      this.ACTIVITY_THRESHOLD_MS,
    );
  }

  // ΓöÇΓöÇ IMAP Polling Logic ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  /**
   * Connect to IMAP, fetch UNSEEN emails, process each through normalizer.
   */
  private async pollMailbox(config: any): Promise<void> {
    let ImapFlow: any;
    try {
      // Dynamic import ΓÇö imapflow is an ESM package
      ImapFlow = (await import('imapflow')).ImapFlow;
    } catch {
      this.logger.error(
        '[ImapPoller] imapflow package not installed. Run: npm install imapflow',
      );
      return;
    }

    // Decrypt credentials
    let credentials: Record<string, any>;
    try {
      credentials = JSON.parse(
        await this.crypto.decrypt(config.encryptedCredentials),
      );
      credentials = await this.oauth2TokenManager.buildOAuth2Credentials(
        config,
        credentials,
      );
    } catch (err: any) {
      this.logger.error(
        `[ImapPoller] Failed to decrypt credentials for ${config.name}: ${err.message}`,
      );
      return;
    }

    const imapHost = config.publicSettings?.imapHost;
    const imapPort = Number(config.publicSettings?.imapPort || 993);

    if (!imapHost) return;

    const auth =
      (config.authType || 'app_password') === 'oauth2'
        ? {
            user: credentials.user,
            accessToken: credentials.accessToken,
          }
        : {
            user: credentials.user,
            pass: credentials.password,
          };

    const client = new ImapFlow({
      host: imapHost,
      port: imapPort,
      secure: imapPort === 993,
      auth,
      logger: false, // Suppress noisy IMAP protocol logs
      // Network safety: without these, a half-open IMAP socket can hold the
      // mailbox lock indefinitely and the poller never recovers until
      // process restart.
      socketTimeout: 30_000,
      greetingTimeout: 15_000,
    } as any);

    try {
      await client.connect();

      const syncTargetFolders = await this.emailSettings.getSyncTargetFolders(
        config.tenantId,
      );

      if (!syncTargetFolders.includes('INBOX')) {
        this.logger.debug(
          `[ImapPoller] ${config.name}: INBOX is not in syncTargetFolders; skipping mailbox poll`,
        );
        return;
      }

      // Open INBOX. Additional provider-specific folder paths can be layered
      // here once Gmail/Graph adapters expose stable folder/label discovery.
      const lock = await client.getMailboxLock('INBOX');

      try {
        // ΓöÇΓöÇ UID-based tracking (never miss read emails) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
        // Instead of { seen: false } which misses emails the user already
        // opened in Gmail/Outlook, track the last processed UID in Redis
        // and fetch everything newer.
        const uidCacheKey = `imap:lastuid:${config.id}`;
        const redisClient = this.redisService.getClient();
        const lastUidStr = await redisClient.get(uidCacheKey);
        const lastUid = lastUidStr ? parseInt(lastUidStr, 10) : 0;

        // Fetch tenant-specific settings from channel config
        const initialSyncDays =
          parseInt(config.publicSettings?.initialSyncDays) || 30;
        const blockAutoResponders =
          config.publicSettings?.blockAutoResponders === true ||
          config.publicSettings?.blockAutoResponders === 'true';

        // Build fetch range: all UIDs > lastUid, or ALL from last N days if first run
        // First run fetches ALL emails (read + unread) to ensure complete mailbox sync.
        // Subsequent runs use UID-based tracking to never miss emails.
        const fetchQuery =
          lastUid > 0
            ? { uid: `${lastUid + 1}:*` }
            : {
                since: new Date(
                  Date.now() - initialSyncDays * 24 * 60 * 60 * 1000,
                ),
              };

        // Fetch messages
        const messages: any[] = [];
        for await (const msg of client.fetch(fetchQuery, {
          envelope: true,
          source: true,
          bodyStructure: true,
          labels: true,
        })) {
          messages.push(msg);
          if (messages.length >= this.MAX_BATCH_SIZE) break;
        }

        if (messages.length === 0) {
          return;
        }

        this.logger.log(
          `[ImapPoller] ${config.name}: Found ${messages.length} new email(s)`,
        );

        // Cap batch size to avoid lock expiration and overload
        const batch = messages.slice(0, this.MAX_BATCH_SIZE);
        if (messages.length > this.MAX_BATCH_SIZE) {
          this.logger.warn(
            `[ImapPoller] ${config.name}: Processing first ${this.MAX_BATCH_SIZE} of ${messages.length} emails (rest will sync next cycle)`,
          );
        }

        // Record tenant activity (keeps polling at 2min)
        await this.recordActivity(config.tenantId);

        // Process each message
        let processed = 0;
        const processedUids: number[] = [];
        for (const msg of batch) {
          // Graceful shutdown: stop processing remaining emails
          if (this.destroying) {
            this.logger.warn(
              `[ImapPoller] Shutdown in progress ΓÇö aborting remaining email(s) for ${config.name}`,
            );
            break;
          }

          try {
            this.logger.log(
              `[ImapPoller] Γû╢ Processing UID=${msg.uid} (${config.name})`,
            );
            const gmailLabels = this.buildGmailLabelContext(msg.labels);
            await this.processEmail(config, msg, client, blockAutoResponders, {
              crmFolder: 'INBOX',
              providerFolder: 'INBOX',
              providerLabelIds: gmailLabels.providerLabelIds,
              providerLabels: gmailLabels.providerLabels,
            });
            processedUids.push(msg.uid);
            processed++;
          } catch (err: any) {
            this.logger.error(
              `[ImapPoller] Failed to process email UID=${msg.uid}: ${err.message}`,
            );
          }
        }

        if (processed > 0) {
          this.logger.log(
            `[ImapPoller] ${config.name}: Successfully processed ${processed}/${batch.length} email(s)`,
          );
        }

        // Save highest UID from this batch for next poll cycle
        // Crucial: Use 'batch' here, not 'messages'. If we use 'messages',
        // we skip emails that were fetched but not yet processed due to batch limits.
        const maxUid = Math.max(...batch.map((m: any) => m.uid));
        if (maxUid > 0) {
          await redisClient.set(uidCacheKey, maxUid.toString());
        }
      } finally {
        lock.release();
      }
    } catch (err: any) {
      this.logger.error(
        `[ImapPoller] IMAP connection failed for ${config.name} (${imapHost}:${imapPort}): ${err.message}`,
      );
    } finally {
      await client.logout().catch(() => {});
    }
  }

  // ΓöÇΓöÇ Email Processing ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  /**
   * Process a single fetched email through the normalizer pipeline.
   */
  private async processEmail(
    config: any,
    msg: any,
    _imapClient: any,
    blockAutoResponders: boolean = false,
    mailboxContext: MailboxLabelContext = {
      crmFolder: 'INBOX',
      providerFolder: 'INBOX',
      providerLabelIds: ['INBOX'],
      providerLabels: ['Inbox'],
    },
  ): Promise<void> {
    // ΓöÇΓöÇ Early Duplicate Check (from envelope, no parsing needed) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const envelopeMessageId = msg.envelope?.messageId;
    if (envelopeMessageId) {
      const existing = await this.emailMetadataModel
        .findOne({
          tenantId: config.tenantId,
          emailMessageId: envelopeMessageId,
        })
        .lean();
      if (existing) {
        await this.refreshDuplicateEmailLabels(
          config,
          msg,
          existing,
          mailboxContext,
          envelopeMessageId,
        );
        this.logger.warn(
          `[ImapPoller] UID=${msg.uid}: Skipped duplicate (envelope) ΓÇö ${envelopeMessageId}`,
        );
        return;
      }
    }

    // ΓöÇΓöÇ Parse email using mailparser (proper MIME/QP/Base64 decoding) ΓöÇΓöÇ
    const rawSource = msg.source;
    const rawSize = Buffer.isBuffer(rawSource)
      ? rawSource.length
      : rawSource
        ? Buffer.byteLength(String(rawSource))
        : 0;
    if (!rawSource) {
      this.logger.warn(
        `[ImapPoller] UID=${msg.uid}: No source data ΓÇö skipping`,
      );
      return;
    }

    if (rawSize > this.MAX_RAW_EMAIL_BYTES) {
      this.logger.warn(
        `[ImapPoller] UID=${msg.uid}: Raw email too large (${rawSize} bytes) - skipping to avoid OOM`,
      );
      return;
    }

    this.logger.log(`[ImapPoller] UID=${msg.uid}: Parsing (${rawSize} bytes)`);
    // simpleParser has no internal timeout ΓÇö a malformed MIME or a
    // pathological boundary section can hang the worker. Race it against a
    // 30s timer so a single bad message does not stall the mailbox lock.
    const parsePromise = simpleParser(rawSource, {
      skipImageLinks: true,
      skipHtmlToText: false,
      skipTextToHtml: false,
    });
    const parsed: ParsedMail = await Promise.race([
      parsePromise,
      new Promise<ParsedMail>((_, reject) =>
        setTimeout(
          () => reject(new Error('simpleParser timed out after 30s')),
          30_000,
        ).unref(),
      ),
    ]);
    this.logger.log(
      `[ImapPoller] UID=${msg.uid}: Parsed OK ΓÇö subject="${parsed.subject || '(none)'}"`,
    );

    // Extract properly decoded content
    const htmlBody = parsed.html || '';
    const textBody = parsed.text || '';
    const subject = parsed.subject || msg.envelope?.subject || '(no subject)';

    // ΓöÇΓöÇ Extract structured participant data from mailparser ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    // mailparser returns AddressObject with { value: [{ address, name }] }
    // to/cc/bcc can be AddressObject | AddressObject[] ΓÇö normalize to flat array
    const extractAddresses = (field: any): string[] => {
      if (!field) return [];
      const items = Array.isArray(field) ? field : [field];
      return items.flatMap((obj: any) =>
        (obj.value || []).map((a: any) => a.address).filter(Boolean),
      );
    };
    const fromAddr = parsed.from?.value?.[0]?.address || '';
    const fromName =
      parsed.from?.value?.[0]?.name || fromAddr.split('@')[0] || 'Unknown';
    const toAddrs = extractAddresses(parsed.to);
    const ccAddrs = extractAddresses(parsed.cc);
    const bccAddrs = extractAddresses(parsed.bcc);

    // Build headers map for normalizer compatibility (auto-responder, bounce, thread)
    // Only use string-safe headers ΓÇö skip structured objects (from/to/cc)
    const headers: Record<string, string> = {};
    parsed.headers.forEach((value, key) => {
      const k = key.toLowerCase();
      // Skip address fields ΓÇö we use parsed.from/to/cc directly
      if (['from', 'to', 'cc', 'bcc', 'sender', 'reply-to'].includes(k)) {
        headers[k] =
          typeof value === 'object' && value !== null && 'text' in value
            ? (value as any).text
            : String(value ?? '');
        return;
      }
      headers[k] =
        typeof value === 'string'
          ? value
          : Array.isArray(value)
            ? value.join(', ')
            : String(value ?? '');
    });

    // ΓöÇΓöÇ Sad Path #1: Auto-Responder Filter ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    if (
      blockAutoResponders &&
      this.normalizer.isAutoResponder(headers, blockAutoResponders)
    ) {
      this.logger.warn(`[ImapPoller] Dropped auto-responder: ${subject}`);
      return;
    }

    // ΓöÇΓöÇ Sad Path #2: Bounce Detection ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const bounce = this.normalizer.detectBounce(headers, textBody);
    if (bounce?.isBounce) {
      this.normalizer.handleBounce(
        config.tenantId,
        bounce.originalMessageId,
        bounce.reason,
      );
      return;
    }

    // ΓöÇΓöÇ Extract Threading ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const threadInfo = this.normalizer.extractThreadInfo(headers);

    // ΓöÇΓöÇ Generate clean snippet from plain text ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    // Use parsed.text (already decoded by mailparser) ΓÇö no CSS/HTML artifacts
    const snippet = (textBody || '')
      .replace(/\s+/g, ' ')
      .trim()
      .substring(0, 200);

    // ΓöÇΓöÇ Idempotency Guard: skip if already imported ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const rfcMessageId = threadInfo.messageId;
    if (rfcMessageId) {
      const existing = await this.emailMetadataModel
        .findOne({
          tenantId: config.tenantId,
          emailMessageId: rfcMessageId,
        })
        .lean();
      if (existing) {
        await this.refreshDuplicateEmailLabels(
          config,
          msg,
          existing,
          mailboxContext,
          rfcMessageId,
        );
        this.logger.warn(
          `[ImapPoller] Skipped duplicate: ${rfcMessageId} (already imported)`,
        );
        return;
      }
    }

    // ΓöÇΓöÇ Generate a placeholder messageId upfront ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const generatedMessageId = new Types.ObjectId();

    // ΓöÇΓöÇ Save heavy content to email_contents ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const emailContent = await this.emailContentModel.create({
      tenantId: config.tenantId,
      messageId: generatedMessageId,
      contactIds: [],
      subject,
      htmlBody: htmlBody || '',
      textBody: textBody || '',
      attachments: [],
      from: fromAddr,
      to: toAddrs,
      cc: ccAddrs,
      rfc822MessageId: threadInfo.messageId || null,
    });

    // ΓöÇΓöÇ Save metadata to email_metadata ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const providerLabelDetails = this.buildProviderLabelDetails(mailboxContext);

    let emailMetadata: any;
    try {
      emailMetadata = await this.emailMetadataModel.create({
        tenantId: config.tenantId,
        mailboxId: config.id,
        messageId: generatedMessageId,
        emailMessageId:
          threadInfo.messageId || `<imap-${generatedMessageId}@local>`,
        inReplyTo: threadInfo.inReplyTo,
        references: threadInfo.references,
        from: fromAddr,
        to: toAddrs,
        cc: ccAddrs,
        bcc: bccAddrs,
        crmFolder: mailboxContext.crmFolder,
        providerFolder: mailboxContext.providerFolder,
        providerLabelIds: mailboxContext.providerLabelIds,
        providerLabels: mailboxContext.providerLabels,
        providerLabelDetails,
        deliveryStatus: 'unknown',
        bounceReason: null,
        imapUid: msg.uid || null,
        syncStatus: null,
        lastSyncError: null,
      });
    } catch (err: any) {
      if (err.code === 11000) {
        await this.emailContentModel
          .deleteOne({ _id: emailContent._id })
          .catch(() => {});
        const existing = threadInfo.messageId
          ? await this.emailMetadataModel
              .findOne({
                tenantId: config.tenantId,
                emailMessageId: threadInfo.messageId,
              })
              .lean()
          : null;
        if (existing) {
          await this.refreshDuplicateEmailLabels(
            config,
            msg,
            existing,
            mailboxContext,
            threadInfo.messageId,
          );
        }
        this.logger.debug(
          `[ImapPoller] Skipped duplicate (race): ${threadInfo.messageId}`,
        );
        return;
      }
      throw err;
    }

    // ΓöÇΓöÇ Emit lightweight payload to OmniInbound pipeline ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    this.eventEmitter.emit('email.inbound.received', {
      tenantId: config.tenantId,
      configId: config.id,
      channelType: 'email',
      generatedMessageId: generatedMessageId.toString(),
      from: fromAddr,
      fromName,
      to: toAddrs,
      cc: ccAddrs,
      subject,
      snippet,
      threadInfo,
      emailContentId: emailContent._id?.toString(),
      emailMetadataId: emailMetadata._id?.toString(),
      mailboxId: config.id,
      crmFolder: mailboxContext.crmFolder,
      providerFolder: mailboxContext.providerFolder,
      providerLabelIds: mailboxContext.providerLabelIds,
      providerLabels: mailboxContext.providerLabels,
      providerLabelDetails,
      imapUid: msg.uid || null,
      timestamp: parsed.date || new Date(),
    });

    this.eventEmitter.emit('email.labels.observed', {
      tenantId: config.tenantId,
      mailboxId: config.id,
      provider: config.providerType,
      labels: providerLabelDetails,
    });

    this.logger.log(
      `[ImapPoller] Γ£ë∩╕Å Processed: "${subject}" from ${fromName} <${fromAddr}>`,
    );
  }

  // ΓöÇΓöÇ Config Discovery ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  private async refreshDuplicateEmailLabels(
    config: any,
    msg: any,
    existing: any,
    mailboxContext: MailboxLabelContext,
    messageIdForLog: string,
  ): Promise<void> {
    const providerLabelDetails = this.buildProviderLabelDetails(mailboxContext);
    const existingLabelIds = this.normalizeLabelSet(existing.providerLabelIds);
    const nextLabelIds = this.normalizeLabelSet(
      mailboxContext.providerLabelIds,
    );
    const labelsChanged = !this.sameStringArray(existingLabelIds, nextLabelIds);

    await this.emailMetadataModel
      .updateOne(
        { _id: existing._id },
        {
          $set: {
            mailboxId: existing.mailboxId || config.id,
            crmFolder: mailboxContext.crmFolder,
            providerFolder: mailboxContext.providerFolder,
            providerLabelIds: mailboxContext.providerLabelIds,
            providerLabels: mailboxContext.providerLabels,
            providerLabelDetails,
            imapUid: msg.uid || existing.imapUid || null,
          },
        },
      )
      .exec();

    await this.omniMessageModel
      .updateOne(
        {
          tenantId: config.tenantId,
          externalMessageId: existing.emailMessageId,
        },
        {
          $set: {
            'metadata.mailboxId': existing.mailboxId || config.id,
            'metadata.crmFolder': mailboxContext.crmFolder,
            'metadata.providerFolder': mailboxContext.providerFolder,
            'metadata.providerLabelIds': mailboxContext.providerLabelIds,
            'metadata.providerLabels': mailboxContext.providerLabels,
            'metadata.providerLabelDetails': providerLabelDetails,
          },
        },
      )
      .exec();

    const newlyObservedLabels = providerLabelDetails.filter(
      (label) => !existingLabelIds.includes(label.id),
    );
    if (newlyObservedLabels.length > 0) {
      this.eventEmitter.emit('email.labels.observed', {
        tenantId: config.tenantId,
        mailboxId: config.id,
        provider: config.providerType,
        labels: newlyObservedLabels,
      });
    }

    if (labelsChanged) {
      this.logger.log(
        `[ImapPoller] UID=${msg.uid}: Refreshed labels for duplicate ${messageIdForLog}`,
      );
    }
  }

  private buildProviderLabelDetails(
    mailboxContext: MailboxLabelContext,
  ): ProviderLabelDetail[] {
    return mailboxContext.providerLabelIds.map((id, index) => ({
      id,
      name: mailboxContext.providerLabels[index] || id,
      type: this.detectProviderLabelType(id),
      color: null,
    }));
  }

  private detectProviderLabelType(labelId: string): 'system' | 'user' {
    return [
      'INBOX',
      'SENT',
      'DRAFTS',
      'TRASH',
      'SPAM',
      'ARCHIVE',
      'UNREAD',
      'STARRED',
      'IMPORTANT',
    ].includes(labelId.toUpperCase())
      ? 'system'
      : 'user';
  }

  private normalizeLabelSet(labels?: string[]): string[] {
    return [...new Set((labels || []).filter(Boolean))].sort();
  }

  private sameStringArray(left: string[], right: string[]): boolean {
    return (
      left.length === right.length &&
      left.every((value, index) => value === right[index])
    );
  }

  private buildGmailLabelContext(labels?: Set<string>): {
    providerLabelIds: string[];
    providerLabels: string[];
  } {
    const rawLabels = labels ? Array.from(labels) : [];
    const normalized = rawLabels
      .map((label) => this.normalizeProviderLabel(label))
      .filter((label) => label.id && !label.id.startsWith('[Gmail]/'));

    if (!normalized.some((label) => label.id === 'INBOX')) {
      normalized.unshift({ id: 'INBOX', name: 'Inbox' });
    }

    return {
      providerLabelIds: normalized.map((label) => label.id),
      providerLabels: normalized.map((label) => label.name),
    };
  }

  private normalizeProviderLabel(label: string): { id: string; name: string } {
    const trimmed = String(label || '').trim();
    if (!trimmed) return { id: '', name: '' };

    if (trimmed === '\\Inbox' || trimmed.toUpperCase() === 'INBOX') {
      return { id: 'INBOX', name: 'Inbox' };
    }
    if (trimmed === '\\Sent' || trimmed.toUpperCase() === 'SENT') {
      return { id: 'SENT', name: 'Sent' };
    }
    if (trimmed === '\\Draft' || trimmed.toUpperCase() === 'DRAFTS') {
      return { id: 'DRAFTS', name: 'Drafts' };
    }
    if (trimmed === '\\Trash' || trimmed.toUpperCase() === 'TRASH') {
      return { id: 'TRASH', name: 'Trash' };
    }
    if (trimmed === '\\Junk' || trimmed.toUpperCase() === 'SPAM') {
      return { id: 'SPAM', name: 'Spam' };
    }

    const withoutSlash = trimmed.startsWith('\\') ? trimmed.slice(1) : trimmed;
    return { id: withoutSlash, name: withoutSlash };
  }

  /**
   * Find all SMTP channel configs that have IMAP sync enabled.
   * A config is IMAP-enabled if publicSettings.imapHost is non-empty.
   */
  private async findImapEnabledConfigs(): Promise<any[]> {
    try {
      // Use raw Mongoose query since repo doesn't have this filter
      const ChannelConfigModel =
        this.configRepo['configModel'] || (this.configRepo as any).model;

      if (!ChannelConfigModel) {
        // Fallback: scan visible configs
        return [];
      }

      const configs = await ChannelConfigModel.find({
        providerType: 'smtp',
        deletedAt: null,
        status: 'active',
        'publicSettings.imapHost': { $exists: true, $ne: '' },
      })
        .select('+encryptedCredentials +accessToken +refreshToken')
        .setOptions({ isPlatformQuery: true } as any)
        .lean();

      // .lean() strips Mongoose virtuals ΓÇö add `id` from `_id`
      return configs.map((c: any) => ({
        ...c,
        id: c._id?.toString(),
        tenantId: c.tenantId?.toString(),
      }));
    } catch (err: any) {
      this.logger.error(`[ImapPoller] Config scan error: ${err.message}`);
      return [];
    }
  }

  // ΓöÇΓöÇ Basic Email Parsers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  // parseHeaders and parseBody are now handled by mailparser in processEmail()
}

import { Logger } from '@nestjs/common';
import { OnWorkerEvent } from '@nestjs/bullmq';
import type { Job } from 'bullmq';
import { Connection, Model } from 'mongoose';
import { ClsService } from 'nestjs-cls';
import Redis from 'ioredis';

import { BaseTenantConsumer } from '../../queue/base-tenant.consumer';
import {
  BaseExportJobData,
  ExportCancelledError,
  ExportColumn,
  ExportLimitExceededError,
  ExportModuleConfig,
  ExportResult,
  SecondaryUnavailableError,
} from './types';
import { ExportStorageService } from './export-storage.service';
import { ExportMaskingService, ExportMasker } from './export-masking.service';
import { ExportProgressTracker } from './export-progress.service';
import { createExportWriter } from './format/export-format.factory';
import { RedisLockService } from '../../redis/redis-lock.service';

const LOCK_TTL_MS = 10 * 60 * 1000; // 10 min, heartbeat-renewed by lock service
const COUNT_MAX_TIME_MS = 3_000; // cap the progress-count query
const DOWNLOAD_TTL_SECONDS = Number(
  process.env.EXPORT_DOWNLOAD_TTL_SECONDS ?? 24 * 60 * 60,
);
const READ_PREFERENCE =
  process.env.EXPORT_READ_PREFERENCE ?? 'secondaryPreferred';

/** Mongoose cursor shape the engine consumes. */
export type ExportCursor = AsyncIterable<Record<string, any>> & {
  close(): Promise<void>;
};

export interface ExportQueryOptions {
  projection: Record<string, 1>;
  readPreference: string;
  batchSize: number;
}

/**
 * Abstract base for ALL export processors (Template Method).
 *
 * The shared engine owns the entire pipeline:
 *   acquire per-tenant lock ΓåÆ mask snapshot ΓåÆ count ΓåÆ stream cursor ΓåÆ
 *   format rows (backpressure) ΓåÆ upload (stream straight to S3 / temp on local)
 *   ΓåÆ publish completion ΓåÆ persist history. Subclasses only:
 *     - provide the module config
 *     - open a lean, projected cursor for the typed filter
 *     - provide a progress count
 *     - expose injected dependencies
 */
export abstract class BaseExportProcessor<
  TJobData extends BaseExportJobData = BaseExportJobData,
> extends BaseTenantConsumer<TJobData, ExportResult> {
  protected abstract readonly logger: Logger;
  protected abstract readonly cls: ClsService;

  protected abstract getModuleConfig(): ExportModuleConfig;
  protected abstract getStorage(): ExportStorageService;
  protected abstract getExportJobModel(): Model<any>;
  protected abstract getLockService(): RedisLockService;
  protected abstract getRedis(): Redis;
  protected abstract getMaskingService(): ExportMaskingService;
  protected abstract getConnection(): Connection;

  /** Open a lean, projected, read-preference-tagged cursor for the filter. */
  protected abstract openCursor(
    data: TJobData,
    opts: ExportQueryOptions,
  ): ExportCursor;

  /** Count matching docs for progress (engine wraps with a time budget). */
  protected abstract countForProgress(
    data: TJobData,
    maxTimeMS: number,
  ): Promise<number>;

  /**
   * Optional lifecycle hook called once per job, after masking / progress setup
   * but before the streaming cursor opens. Subclasses override this to pre-load
   * lookup maps (users, stages, statuses, etc.) so that `ExportColumn.format`
   * functions can resolve ObjectId references to human-readable values.
   *
   * The default implementation is a no-op.
   */
  protected async beforeExport(_data: TJobData): Promise<void> {
    // no-op ΓÇö subclasses may override
  }

  // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ LIFECYCLE HOOKS ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  @OnWorkerEvent('failed')
  async onFailed(job: Job<TJobData>, error: Error) {
    void super.onFailed(job, error);
    const cancelled = error instanceof ExportCancelledError;
    await this.patchJob(String(job.id), {
      status: cancelled ? 'cancelled' : 'failed',
      failedReason: cancelled ? undefined : error.message,
      cancelledAt: cancelled ? new Date() : undefined,
      completedAt: new Date(),
    });
  }

  // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ MAIN PIPELINE ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  protected async handle(job: Job<TJobData>): Promise<ExportResult> {
    const cfg = this.getModuleConfig();
    const lockKey = `lock:export:${cfg.module}:${job.data.tenantId}`;
    return this.getLockService().acquire(
      lockKey,
      { ttl: LOCK_TTL_MS },
      (signal) => this.runExport(job, signal),
    );
  }

  private async runExport(
    job: Job<TJobData>,
    signal: AbortSignal,
  ): Promise<ExportResult> {
    const data = job.data;
    const cfg = this.getModuleConfig();
    const format = data.format;
    const cap = cfg.hardCap[format];
    const gzip = format === 'csv' && cfg.gzipCsv;

    const columns = this.resolveColumns(cfg, data.columns);
    const progress = new ExportProgressTracker(
      this.getExportJobModel(),
      this.getRedis(),
      String(job.id),
    );

    await progress.update({ status: 'active', startedAt: new Date() });
    await this.assertSecondaryIfRequired();

    const masker = await this.getMaskingService().buildMasker(
      data.tenantId,
      data.userGroupId,
      cfg.maskingResource,
    );

    await this.beforeExport(data);

    const estimatedTotal = await this.safeCount(data);

    const sink = await this.getStorage().openSink(
      this.buildFilename(cfg, format, gzip),
      {
        contentType: this.contentType(format, gzip),
        gzip,
        ttlSeconds: DOWNLOAD_TTL_SECONDS,
      },
    );
    const writer = createExportWriter(format, sink.writable);

    let cursor: ExportCursor | null = null;
    let processed = 0;
    try {
      await writer.writeHeader(columns.map((c) => c.header));

      cursor = this.openCursor(data, {
        projection: this.buildProjection(columns),
        readPreference: READ_PREFERENCE,
        batchSize: cfg.batchSize,
      });

      for await (const doc of cursor) {
        await writer.writeRow(this.buildRow(columns, doc, masker));
        processed++;

        if (processed > cap) {
          throw new ExportLimitExceededError(cap);
        }
        if (processed % cfg.batchSize === 0) {
          if (signal.aborted) throw new Error('Export lock lost');
          if (await progress.isCancelled()) throw new ExportCancelledError();
          await progress.report(job, processed, estimatedTotal);
          await this.delay(cfg.throttleMs);
        }
      }

      await writer.finalize();
      const file = await sink.finalize();
      await progress.complete(job, processed);

      await this.getRedis().publish(
        cfg.completionChannel,
        JSON.stringify({
          tenantId: data.tenantId,
          userId: data.userId,
          jobId: String(job.id),
          downloadUrl: file.downloadUrl,
          expiresAt: file.expiresAt,
          recordCount: processed,
        }),
      );

      await progress.update({
        status: 'completed',
        recordCount: processed,
        downloadUrl: file.downloadUrl,
        fileExpiresAt: new Date(file.expiresAt),
        progress: { processed, total: processed, pct: 100 },
        completedAt: new Date(),
      });

      this.logger.log(
        `Export job ${job.id} (${cfg.module}) done: ${processed} records`,
      );

      return {
        jobId: String(job.id),
        recordCount: processed,
        downloadUrl: file.downloadUrl,
        expiresAt: file.expiresAt,
        storageKey: file.storageKey,
        format,
      };
    } catch (err) {
      await sink.abort();
      throw err;
    } finally {
      await cursor?.close().catch(() => undefined);
      await ExportProgressTracker.clearCancel(
        this.getRedis(),
        String(job.id),
      ).catch(() => undefined);
    }
  }

  // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ HELPERS ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  private buildRow(
    columns: ExportColumn[],
    doc: Record<string, any>,
    masker: ExportMasker,
  ): string[] {
    return columns.map((col) => {
      const raw = this.getByPath(doc, col.path);
      const value = masker.active
        ? masker.maskValue(col.maskKey ?? col.path, raw)
        : raw;
      return col.format ? col.format(value, doc) : this.defaultCell(value);
    });
  }

  private resolveColumns(
    cfg: ExportModuleConfig,
    requested?: string[],
  ): ExportColumn[] {
    if (!requested || requested.length === 0) return [...cfg.columns];
    const allowed = new Set(
      requested.filter((c) => cfg.selectableColumns.has(c)),
    );
    const cols = cfg.columns.filter((c) => allowed.has(c.path));
    return cols.length ? cols : [...cfg.columns];
  }

  private buildProjection(columns: ExportColumn[]): Record<string, 1> {
    const projection: Record<string, 1> = {};
    for (const col of columns) {
      const field = col.path === 'id' ? '_id' : col.path.split('.')[0];
      projection[field] = 1;
    }
    return projection;
  }

  private getByPath(doc: Record<string, any>, path: string): unknown {
    if (path === 'id') return doc._id;
    if (!path.includes('.')) return doc[path];
    return path
      .split('.')
      .reduce<any>((o, k) => (o == null ? undefined : o[k]), doc);
  }

  private defaultCell(value: unknown): string {
    if (value == null) return '';
    if (Array.isArray(value))
      return value.map((v) => this.scalar(v)).join('; ');
    return this.scalar(value);
  }

  private scalar(value: unknown): string {
    if (value == null) return '';
    if (value instanceof Date) return value.toISOString();
    return String(value);
  }

  private contentType(format: string, gzip: boolean): string {
    if (gzip) return 'application/gzip';
    if (format === 'xlsx') {
      return 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet';
    }
    return 'text/csv; charset=utf-8';
  }

  private buildFilename(
    cfg: ExportModuleConfig,
    format: string,
    gzip: boolean,
  ): string {
    const date = new Date().toISOString().slice(0, 10);
    const base = `${cfg.module}s-export-${date}.${format}`;
    return gzip ? `${base}.gz` : base;
  }

  private async safeCount(data: TJobData): Promise<number | null> {
    try {
      const n = await this.countForProgress(data, COUNT_MAX_TIME_MS);
      return n > 0 ? n : null;
    } catch {
      // count too slow / errored ΓÇö fall back to processed-only progress.
      return null;
    }
  }

  private async assertSecondaryIfRequired(): Promise<void> {
    if (process.env.EXPORT_REQUIRE_SECONDARY !== 'true') return;
    try {
      const db = this.getConnection().db;
      const hello: any = await db?.admin().command({ hello: 1 });
      const members =
        (hello?.hosts?.length ?? 0) + (hello?.passives?.length ?? 0);
      if (hello?.setName && members > 1) return;
    } catch {
      // fall through to throw ΓÇö we cannot confirm a secondary exists
    }
    throw new SecondaryUnavailableError();
  }

  private async patchJob(
    bullJobId: string,
    patch: Record<string, any>,
  ): Promise<void> {
    try {
      // Runs from the 'failed' worker event ΓÇö OUTSIDE the tenant CLS wrapper.
      // bullJobId is globally unique, so a platform query is safe here.
      await this.getExportJobModel().updateOne({ bullJobId }, { $set: patch }, {
        isPlatformQuery: true,
      } as any);
    } catch (err) {
      this.logger.warn(
        `Failed to update export history (bullJobId=${bullJobId}): ${(err as Error).message}`,
      );
    }
  }

  private delay(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }
}

import {
  CanActivate,
  ExecutionContext,
  Injectable,
  UnauthorizedException,
} from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { Request } from 'express';
import { ClsService } from 'nestjs-cls';

/**
 * Guards endpoints that should only be called by internal services
 * (e.g. crm-manager-api ΓåÆ crm-api). Validates the X-Internal-Api-Key header.
 *
 * Set INTERNAL_API_KEY in env. If unset in development the guard skips validation
 * so local dev doesn't break, but in production the key is required.
 */
@Injectable()
export class InternalApiKeyGuard implements CanActivate {
  constructor(
    private readonly configService: ConfigService,
    private readonly cls: ClsService,
  ) {}

  canActivate(context: ExecutionContext): boolean {
    const expectedKey = this.configService.get<string>('INTERNAL_API_KEY', {
      infer: true,
    });

    if (!expectedKey) {
      if (process.env.NODE_ENV === 'production') {
        throw new UnauthorizedException(
          'INTERNAL_API_KEY is not configured on this server',
        );
      }
      // Dev/test: allow through with a warning logged once at startup
      return true;
    }

    const request = context.switchToHttp().getRequest<Request>();
    const provided = request.headers['x-internal-api-key'];
    const key = Array.isArray(provided) ? provided[0] : provided;

    // LOW-02/LOW-03: Use constant-time comparison to prevent timing attacks.
    // A plain `!==` leaks key material byte-by-byte via response latency.
    if (
      !key ||
      key.length !== expectedKey.length ||
      !require('crypto').timingSafeEqual(
        Buffer.from(key),
        Buffer.from(expectedKey),
      )
    ) {
      throw new UnauthorizedException('Invalid or missing internal API key');
    }

    // Audit trail: mark this request as API-key-initiated
    this.cls.set('executionSource', 'A');
    this.cls.set('sourceContext', { keyId: 'INTERNAL_API_KEY' });

    return true;
  }
}

import { Logger } from '@nestjs/common';
import { OnWorkerEvent } from '@nestjs/bullmq';
import type { Job } from 'bullmq';
import { Model, Connection } from 'mongoose';
import { ClsService } from 'nestjs-cls';
import { EventEmitter2 } from '@nestjs/event-emitter';
import Redis from 'ioredis';
import { Readable } from 'stream';

import { BaseTenantConsumer } from '../../queue/base-tenant.consumer';
import {
  BaseImportJobData,
  DedupMatchingField,
  DedupPolicy,
  ImportErrorCode,
  ImportModuleConfig,
  ImportPreview,
  ImportResult,
  ImportRowError,
  ImportSummary,
  MappedRow,
} from './types';
import { ImportStorageService } from './import-storage.service';
import {
  ImportReportService,
  ImportReportWriter,
} from './import-report.service';
import { ImportDedupEngine, DedupConfig } from './import-dedup.service';
import { ImportReferenceResolver } from './import-reference-resolver.service';
import { ImportProgressTracker } from './import-progress.service';
import { createParser, detectFormat } from './import-parser.factory';
import { RedisLockService } from '../../redis/redis-lock.service';

const LOCK_TTL_MS = 10 * 60 * 1000; // 10 min, heartbeat-renewed by lock service
const DEFAULT_THROTTLE_MS = 60; // pause between batches to spare MongoDB CPU

/**
 * Abstract base class for ALL import processors.
 *
 * Uses Template Method pattern: the shared engine handles the entire import
 * pipeline (stream ΓåÆ batch ΓåÆ dedup ΓåÆ validate ΓåÆ write ΓåÆ report), while
 * module-specific processors override abstract methods for:
 *   - Field mapping (mapRow)
 *   - Row validation (validateRow)
 *   - Insert/Update document building (buildInsert, buildOverwrite, buildMerge)
 *   - Dedup value extraction (extractDedupValues)
 *   - Post-write hooks (afterBatchWrite)
 *
 * Subclass convention:
 *   1. Extend this class with your module's job data type
 *   2. Implement all abstract methods
 *   3. Inject required dependencies in the subclass constructor
 *   4. Decorate with @Processor(queueName, { concurrency: N })
 */
export abstract class BaseImportProcessor<
  TJobData extends BaseImportJobData = BaseImportJobData,
> extends BaseTenantConsumer<TJobData, ImportResult> {
  protected abstract readonly logger: Logger;
  protected abstract readonly cls: ClsService;

  /**
   * Module configuration ΓÇö drives the shared engine.
   * Must be set by the subclass constructor or as a class property.
   */
  protected abstract readonly moduleConfig: ImportModuleConfig;

  /** Mongoose model for the target entity (e.g. ContactModel, DealModel). */
  protected abstract getEntityModel(): Model<any>;

  /** Import storage service for this module. */
  protected abstract getStorage(): ImportStorageService;

  /** Import report service for this module. */
  protected abstract getReportService(): ImportReportService;

  /** Redis lock service. */
  protected abstract getLockService(): RedisLockService;

  /** Event emitter for automation events. */
  protected abstract getEventEmitter(): EventEmitter2;

  /** Redis client for pub/sub. */
  protected abstract getRedis(): Redis;

  /** Mongoose connection for reference resolver. */
  protected abstract getConnection(): Connection;

  /** Import job model for progress tracking. */
  protected abstract getImportJobModel(): Model<any>;

  // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ ABSTRACT: Module-specific logic ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  /**
   * Map a raw CSV/XLSX row onto entity fields using the user's column mapping.
   * Must return scalar fields and array fields separately.
   */
  protected abstract mapRow(
    raw: Record<string, string>,
    mapping: Record<string, string>,
    row: number,
  ): MappedRow;

  /**
   * Validate a mapped row beyond required-field checks.
   * Return errors for any module-specific validation failures.
   * The base class already checks required fields.
   */
  protected abstract validateRow(
    mapped: MappedRow,
    data: TJobData,
  ): ImportRowError[];

  /**
   * Extract dedup values from a mapped row for a given matching field.
   * E.g. for contacts, field='emails' returns the mapped row's email values.
   */
  protected abstract extractDedupValues(
    row: MappedRow,
    field: DedupMatchingField,
  ): string[];

  /**
   * Build the insert document for a new record.
   * Must include tenantId, createdById, updatedById, timestamps.
   */
  protected abstract buildInsert(
    mapped: MappedRow,
    data: TJobData,
    now: Date,
    resolvedRefs: Record<string, string>,
  ): Record<string, any>;

  /**
   * Build the $set update for an overwrite (full replace of mapped fields).
   */
  protected abstract buildOverwrite(
    mapped: MappedRow,
    data: TJobData,
    resolvedRefs: Record<string, string>,
  ): Record<string, any>;

  /**
   * Build the update document for a merge (fill empty, append arrays).
   * Return null if the merge produces no changes.
   */
  protected abstract buildMerge(
    mapped: MappedRow,
    existing: any,
    data: TJobData,
    errors: ImportRowError[],
    resolvedRefs: Record<string, string>,
  ): Record<string, any> | null;

  /**
   * Optional hook called after a successful batch write.
   * Use for emitting automation events, activity logs, etc.
   */

  protected async afterBatchWrite(
    affected: Array<{ id?: string; type: 'insert' | 'update'; row: number }>,
    data: TJobData,
  ): Promise<void> {
    // Default: no-op. Override in subclass if needed.
  }

  // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ LIFECYCLE HOOKS ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  /** Update MongoDB history when a job fails. */
  @OnWorkerEvent('failed')
  async onFailed(job: Job<TJobData>, error: Error) {
    void super.onFailed(job, error);
    await this.updateImportJob(String(job.id), {
      status: 'failed',
      failedReason: error.message,
      completedAt: new Date(),
    });
  }

  // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ MAIN PIPELINE ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  protected async handle(job: Job<TJobData>): Promise<ImportResult> {
    const { tenantId } = job.data;
    const lockKey = `lock:${this.moduleConfig.module}:import:${tenantId}`;

    return this.getLockService().acquire(lockKey, LOCK_TTL_MS, () =>
      this.runImport(job),
    );
  }

  private async runImport(job: Job<TJobData>): Promise<ImportResult> {
    const data = job.data;
    const dryRun = data.dryRun ?? false;
    const format = detectFormat(data.fileKey);
    const parser = createParser(format);
    const storage = this.getStorage();
    const reportService = this.getReportService();
    const report = reportService.createWriter(String(job.id), data.tenantId);

    // Initialize reference resolver if this module has reference fields.
    let refResolver: ImportReferenceResolver | undefined;
    if (this.moduleConfig.referenceFields.length > 0) {
      refResolver = new ImportReferenceResolver(
        this.getConnection(),
        data.tenantId,
        this.moduleConfig.referenceFields,
      );
      await refResolver.initialize();
    }

    // Initialize progress tracker.
    const progress = new ImportProgressTracker(
      this.getImportJobModel(),
      String(job.id),
    );

    // Mark as active in MongoDB history.
    await this.updateImportJob(String(job.id), { status: 'active' });

    const summary: ImportSummary = {
      total: 0,
      inserted: 0,
      updated: 0,
      skipped: 0,
      errors: 0,
    };

    const dedupEngine = new ImportDedupEngine();
    const dedupConfig: DedupConfig | undefined = data.deduplication
      ? {
          matchingFields: data.deduplication.matchingFields,
          policy: data.deduplication.policy as DedupPolicy,
        }
      : undefined;

    let stream: Readable | null = null;
    let batch: MappedRow[] = [];
    let rowNum = 0;

    try {
      stream = await storage.openImportStream(data.fileKey);

      for await (const raw of parser.parse(stream)) {
        rowNum++;
        const mapped = this.mapRow(raw, data.mapping, rowNum);
        batch.push(mapped);

        if (batch.length >= this.moduleConfig.batchSize) {
          await this.processBatch(
            batch,
            data,
            dedupEngine,
            dedupConfig,
            refResolver,
            summary,
            report,
            dryRun,
          );
          batch = [];
          await progress.report(job, summary.total, data.estimatedRows);
          await this.delay(DEFAULT_THROTTLE_MS);
        }
      }

      if (batch.length > 0) {
        await this.processBatch(
          batch,
          data,
          dedupEngine,
          dedupConfig,
          refResolver,
          summary,
          report,
          dryRun,
        );
      }
    } finally {
      stream?.destroy();
    }

    // ΓöÇΓöÇ Finalize ΓöÇΓöÇ

    if (dryRun) {
      const preview: ImportPreview = {
        wouldInsert: summary.inserted,
        wouldUpdate: summary.updated,
        wouldSkip: summary.skipped,
        validationErrors: summary.errors,
      };
      await report.discard();
      await progress.complete(job, summary.total);
      await this.updateImportJob(String(job.id), {
        status: 'completed',
        preview,
        progress: { processed: summary.total, total: summary.total, pct: 100 },
        completedAt: new Date(),
      });
      return { jobId: String(job.id), dryRun: true, preview };
    }

    const finalized = await report.finalize(summary);
    await progress.complete(job, summary.total);

    // Publish completion event via Redis pub/sub.
    await this.getRedis().publish(
      this.moduleConfig.completionChannel,
      JSON.stringify({
        tenantId: data.tenantId,
        userId: data.userId,
        jobId: String(job.id),
        fileName: data.fileName,
        summary,
        reportUrl: finalized?.reportUrl,
      }),
    );

    this.logger.log(
      `Import job ${job.id} done: ${JSON.stringify(summary)} ` +
        `(report=${finalized?.reportUrl ?? 'none'})`,
    );

    // Best-effort cleanup of the uploaded source file.
    await storage.deleteImportFile(data.fileKey);

    await this.updateImportJob(String(job.id), {
      status: 'completed',
      summary,
      reportUrl: finalized?.reportUrl,
      progress: { processed: summary.total, total: summary.total, pct: 100 },
      completedAt: new Date(),
    });

    return {
      jobId: String(job.id),
      dryRun: false,
      summary,
      reportUrl: finalized?.reportUrl,
    };
  }

  // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ BATCH PROCESSING ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  private async processBatch(
    batch: MappedRow[],
    data: TJobData,
    dedupEngine: ImportDedupEngine,
    dedupConfig: DedupConfig | undefined,
    refResolver: ImportReferenceResolver | undefined,
    summary: ImportSummary,
    report: ImportReportWriter,
    dryRun: boolean,
  ): Promise<void> {
    const errors: ImportRowError[] = [];
    const ops: any[] = [];
    const opMeta: Array<{ row: number; type: 'insert' | 'update' }> = [];
    const affected: Array<{
      id?: string;
      type: 'insert' | 'update';
      row: number;
    }> = [];

    summary.total += batch.length;

    // ΓöÇΓöÇ Step 1: Required-field validation ΓöÇΓöÇ
    const valid: MappedRow[] = [];
    for (const m of batch) {
      const missing = this.moduleConfig.requiredFields.filter(
        (f) => !m.fields[f] && !(m.arrayFields[f]?.length > 0),
      );
      if (missing.length) {
        summary.errors++;
        errors.push({
          row: m.row,
          code: ImportErrorCode.REQUIRED_FIELD_MISSING,
          field: missing.join(','),
          reason: `Missing required field(s): ${missing.join(', ')}`,
        });
        continue;
      }

      // Module-specific validation.
      const moduleErrors = this.validateRow(m, data);
      if (moduleErrors.length) {
        summary.errors += moduleErrors.length;
        errors.push(...moduleErrors);
        continue;
      }

      valid.push(m);
    }

    // ΓöÇΓöÇ Step 2: Reference resolution ΓöÇΓöÇ
    const resolvedRefs = new Map<number, Record<string, string>>();
    if (refResolver) {
      for (const m of valid) {
        const result = refResolver.resolveRow(m.row, m.fields);
        if (result.errors.length) {
          summary.errors += result.errors.length;
          errors.push(...result.errors);
          // Remove from valid ΓÇö can't insert/update without resolved refs.
          continue;
        }
        resolvedRefs.set(m.row, result.resolved);
      }
    }

    // Filter valid rows to only those with successfully resolved refs.
    const validWithRefs = refResolver
      ? valid.filter((m) => resolvedRefs.has(m.row))
      : valid;

    // ΓöÇΓöÇ Step 3: Dedup lookup ΓöÇΓöÇ
    const dedupMatches = dedupConfig
      ? await dedupEngine.lookupBatch(
          this.getEntityModel(),
          data.tenantId,
          validWithRefs,
          dedupConfig,
          (row, field) => this.extractDedupValues(row, field),
        )
      : null;

    const now = new Date();
    const policy = dedupConfig?.policy;

    for (const m of validWithRefs) {
      const refs = resolvedRefs.get(m.row) ?? {};
      const match = dedupMatches?.get(m.row);

      if (match?.claimedByEarlierRow) {
        summary.skipped++;
        errors.push(dedupEngine.buildDuplicateInFileError(m));
        continue;
      }

      if (!match?.existing) {
        // No match ΓÇö insert new record.
        ops.push({
          insertOne: { document: this.buildInsert(m, data, now, refs) },
        });
        opMeta.push({ row: m.row, type: 'insert' });
        summary.inserted++;
        affected.push({ type: 'insert', row: m.row });
        continue;
      }

      // Matched an existing record ΓÇö apply the chosen policy.
      if (policy === 'skip') {
        summary.skipped++;
        continue;
      }

      if (policy === 'create_new') {
        // Force create a new record even though a duplicate exists.
        ops.push({
          insertOne: { document: this.buildInsert(m, data, now, refs) },
        });
        opMeta.push({ row: m.row, type: 'insert' });
        summary.inserted++;
        affected.push({ type: 'insert', row: m.row });
        continue;
      }

      const update =
        policy === 'overwrite'
          ? this.buildOverwrite(m, data, refs)
          : this.buildMerge(m, match.existing, data, errors, refs);

      if (!update) {
        summary.skipped++;
        continue;
      }

      ops.push({
        updateOne: { filter: { _id: match.existing._id }, update },
      });
      opMeta.push({ row: m.row, type: 'update' });
      summary.updated++;
      affected.push({
        type: 'update',
        id: String(match.existing._id),
        row: m.row,
      });
    }

    // ΓöÇΓöÇ Step 4: Execute bulkWrite (skip for dry-run) ΓöÇΓöÇ
    if (dryRun) {
      await report.appendErrors(errors);
      return;
    }

    if (ops.length > 0) {
      const failed = await this.executeBulk(ops, opMeta, errors, summary);
      // Reconcile counts: failed ops never persisted.
      for (const meta of failed) {
        if (meta.type === 'insert') summary.inserted--;
        else summary.updated--;
      }

      // Post-write hooks (automation events, etc.)
      if (data.triggerAutomations) {
        const failedRows = new Set(failed.map((f) => f.row));
        const successfulAffected = affected.filter(
          (a) => !failedRows.has(a.row),
        );
        await this.afterBatchWrite(successfulAffected, data);
      }
    }

    await report.appendErrors(errors);
  }

  private async executeBulk(
    ops: any[],
    opMeta: Array<{ row: number; type: 'insert' | 'update' }>,
    errors: ImportRowError[],
    summary: ImportSummary,
  ): Promise<Array<{ row: number; type: 'insert' | 'update' }>> {
    const failed: Array<{ row: number; type: 'insert' | 'update' }> = [];
    try {
      await this.getEntityModel().bulkWrite(ops, { ordered: false });
    } catch (err: any) {
      const writeErrors: any[] =
        err?.writeErrors ?? err?.result?.writeErrors ?? [];
      if (writeErrors.length === 0) {
        throw err;
      }
      for (const we of writeErrors) {
        const index = we.index ?? we.err?.index;
        const meta = opMeta[index];
        summary.errors++;
        failed.push(meta);
        errors.push({
          row: meta?.row ?? -1,
          code: ImportErrorCode.DB_WRITE_FAILED,
          reason: `DB write failed: ${we.errmsg ?? we.err?.errmsg ?? 'unknown'}`,
        });
      }
    }
    return failed;
  }

  // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ HELPERS ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  private async updateImportJob(
    bullJobId: string,
    update: Record<string, any>,
  ): Promise<void> {
    try {
      await this.getImportJobModel().updateOne({ bullJobId }, { $set: update });
    } catch (err) {
      this.logger.warn(
        `Failed to update import history (bullJobId=${bullJobId}): ${(err as Error).message}`,
      );
    }
  }

  private delay(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }
}

import { Logger } from '@nestjs/common';

/**
 * Initialize Sentry if the SDK is installed AND `SENTRY_DSN` is configured.
 *
 * Sentry is intentionally an *optional* dependency. We don't want to add a
 * hard `@sentry/node` import to the production build because:
 *   - Many on-prem customers run without it.
 *   - Self-hosted deployments may not have outbound internet for telemetry.
 *
 * If the package isn't resolvable or the DSN is missing, this is a no-op.
 * Otherwise we tag every event with the current service (api/worker/email)
 * and `NODE_ENV` so the Sentry project filters cleanly.
 */
export async function initSentryIfConfigured(): Promise<void> {
  const logger = new Logger('Sentry');
  const dsn = process.env.SENTRY_DSN;
  if (!dsn) {
    return;
  }

  let sentry: any;
  try {
    // Lazy require so the dependency stays optional.
    sentry = await import('@sentry/node').catch(() => null);
    if (!sentry || typeof sentry.init !== 'function') {
      logger.warn(
        '[Sentry] SENTRY_DSN is set but @sentry/node is not installed ΓÇö skipping init',
      );
      return;
    }
  } catch {
    return;
  }

  try {
    sentry.init({
      dsn,
      environment: process.env.NODE_ENV || 'development',
      release: process.env.APP_VERSION || process.env.GIT_SHA,
      tracesSampleRate: Number(process.env.SENTRY_TRACES_RATE) || 0,
      // We do our own secret masking in the logger; Sentry's beforeSend
      // applies the same maskSecrets so anything that escapes a logger call
      // (e.g. uncaught throw) is still scrubbed before leaving the process.
      beforeSend(event: any) {
        try {
          const { maskSecrets } = require('../logger/secret-masker');
          return maskSecrets(event);
        } catch {
          return event;
        }
      },
    });
    sentry.setTag('service', process.env.APP_RUNTIME || 'api');
    logger.log('[Sentry] Initialized');
  } catch (err: any) {
    logger.warn(`[Sentry] Init failed: ${err?.message ?? err}`);
  }
}

import { PermissionGuard } from './permission.guard';
import { PERMISSION_RULE_METADATA } from './permission.decorator';
import { PlatformRoleEnum } from '../../roles/platform-role.enum';
import { createClsMock } from '../../test/mocks/cls.mock';

describe('PermissionGuard', () => {
  let guard: PermissionGuard;
  let reflector: any;
  let authzCache: any;
  let cls: ReturnType<typeof createClsMock>;

  const createContext = (userPayload: any = {}) => {
    const request: any = {
      user: userPayload,
      method: 'GET',
      originalUrl: '/api/contacts',
      headers: {},
    };
    return {
      switchToHttp: () => ({
        getRequest: () => request,
      }),
      getClass: () => ({ name: 'ContactsController' }),
      getHandler: () => ({ name: 'findAll' }),
      request,
    } as any;
  };

  beforeEach(() => {
    reflector = {
      getAllAndOverride: jest.fn(),
    };
    authzCache = {
      canAccess: jest.fn(),
    };
    cls = createClsMock();
    guard = new PermissionGuard(reflector, authzCache, cls as any);
  });

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // NO METADATA ΓÇö public route
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  it('should allow access when no permission metadata is defined', async () => {
    reflector.getAllAndOverride.mockReturnValue(undefined);

    const context = createContext({ sub: 'user_1' });
    const result = await guard.canActivate(context);

    expect(result).toBe(true);
    expect(authzCache.canAccess).not.toHaveBeenCalled();
  });

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // MISSING USER ΓÇö deny
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  it('should deny access when user payload is missing', async () => {
    reflector.getAllAndOverride.mockReturnValue({
      action: 'view',
      resource: 'contacts',
    });
    // Override CLS to have no userId
    cls.get = jest.fn(() => undefined);

    const context = createContext(null);
    const result = await guard.canActivate(context);

    expect(result).toBe(false);
  });

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // SUPER_ADMIN BYPASS
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  it('should bypass permission check for SUPER_ADMIN via realm_access', async () => {
    reflector.getAllAndOverride.mockReturnValue({
      action: 'delete',
      resource: 'contacts',
    });

    const context = createContext({
      sub: 'user_super',
      userId: 'user_super',
      realm_access: { roles: [PlatformRoleEnum.SUPER_ADMIN] },
    });
    const result = await guard.canActivate(context);

    expect(result).toBe(true);
    expect(authzCache.canAccess).not.toHaveBeenCalled();
  });

  it('should bypass permission check for SUPER_ADMIN via roles array', async () => {
    reflector.getAllAndOverride.mockReturnValue({
      action: 'delete',
      resource: 'contacts',
    });

    const context = createContext({
      sub: 'user_super',
      userId: 'user_super',
      roles: [PlatformRoleEnum.SUPER_ADMIN],
    });
    const result = await guard.canActivate(context);

    expect(result).toBe(true);
  });

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // NORMAL USER ΓÇö permission granted
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  it('should allow access when authzCache returns allowed=true', async () => {
    reflector.getAllAndOverride.mockReturnValue({
      action: 'view',
      resource: 'contacts',
    });
    authzCache.canAccess.mockResolvedValue({
      allowed: true,
      userId: 'user_1',
      tenantId: 'tenant_1',
      email: 'test@example.com',
      cacheHit: false,
    });

    const context = createContext({ sub: 'user_1' });
    const result = await guard.canActivate(context);

    expect(result).toBe(true);
    expect(authzCache.canAccess).toHaveBeenCalledWith(
      expect.objectContaining({
        rawUserId: 'user_1',
        rule: { action: 'view', resource: 'contacts' },
      }),
    );
  });

  it('should set CLS context when permission is granted', async () => {
    reflector.getAllAndOverride.mockReturnValue({
      action: 'view',
      resource: 'contacts',
    });
    authzCache.canAccess.mockResolvedValue({
      allowed: true,
      userId: 'user_1',
      tenantId: 'tenant_1',
      email: 'test@example.com',
      cacheHit: false,
    });

    const context = createContext({ sub: 'user_1' });
    await guard.canActivate(context);

    expect(cls.set).toHaveBeenCalledWith('userId', 'user_1');
    expect(cls.set).toHaveBeenCalledWith('tenantId', 'tenant_1');
    expect(cls.set).toHaveBeenCalledWith('activeTenantId', 'tenant_1');
  });

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // NORMAL USER ΓÇö permission denied
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  it('should deny access when authzCache returns allowed=false', async () => {
    reflector.getAllAndOverride.mockReturnValue({
      action: 'delete',
      resource: 'contacts',
    });
    authzCache.canAccess.mockResolvedValue({
      allowed: false,
      userId: 'user_1',
      tenantId: 'tenant_1',
      cacheHit: false,
      denyReason: 'permission_not_granted',
      requiredPermission: 'contacts:delete',
    });

    const context = createContext({ sub: 'user_1' });
    const result = await guard.canActivate(context);

    expect(result).toBe(false);
  });

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // TENANT ISOLATION ΓÇö tenantId resolution
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  it('should pass tenantId from CLS to authzCache', async () => {
    reflector.getAllAndOverride.mockReturnValue({
      action: 'view',
      resource: 'contacts',
    });
    authzCache.canAccess.mockResolvedValue({
      allowed: true,
      userId: 'user_1',
      tenantId: 'tenant_1',
      cacheHit: false,
    });

    const context = createContext({ sub: 'user_1' });
    await guard.canActivate(context);

    expect(authzCache.canAccess).toHaveBeenCalledWith(
      expect.objectContaining({
        tenantHint: 'tenant_1',
      }),
    );
  });

  it('should use X-Tenant-Id header in non-production when CLS is empty', async () => {
    const originalEnv = process.env.NODE_ENV;
    process.env.NODE_ENV = 'development';

    // CLS returns no tenantId
    cls.get = jest.fn((key: string) => {
      if (key === 'userId') return 'user_1';
      return undefined;
    });

    reflector.getAllAndOverride.mockReturnValue({
      action: 'view',
      resource: 'contacts',
    });
    authzCache.canAccess.mockResolvedValue({
      allowed: true,
      userId: 'user_1',
      tenantId: 'tenant_from_header',
      cacheHit: false,
    });

    const context = createContext({ sub: 'user_1' });
    context.switchToHttp().getRequest().headers['x-tenant-id'] =
      'tenant_from_header';

    await guard.canActivate(context);

    expect(authzCache.canAccess).toHaveBeenCalledWith(
      expect.objectContaining({
        tenantHint: 'tenant_from_header',
