// ΓöÇΓöÇ Job data ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

// eslint-disable-next-line @typescript-eslint/no-empty-object-type
export interface DealImportJobData extends BaseImportJobData {
  // Deal-specific tenant settings can be added here (e.g. default pipeline).
}

// ΓöÇΓöÇ Processor ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

@Processor(DEAL_IMPORT_QUEUE, { concurrency: 3 })
export class DealImportProcessor extends BaseImportProcessor<DealImportJobData> {
  protected readonly logger = new Logger(DealImportProcessor.name);
  protected readonly cls: ClsService;
  protected readonly moduleConfig = DEAL_IMPORT_CONFIG;

  private readonly storage: ImportStorageService;
  private readonly reportService: ImportReportService;

  constructor(
    @InjectModel(DealSchemaClass.name)
    private readonly dealModel: Model<DealSchemaDocument>,
    private readonly storageFactory: ImportStorageFactory,
    private readonly lockService: RedisLockService,
    private readonly eventEmitter: EventEmitter2,
    cls: ClsService,
    @Inject(IOREDIS_CLIENT) private readonly redis: Redis,
    @InjectModel(ImportJobSchemaClass.name)
    private readonly importJobModel: Model<ImportJobDocument>,
    @InjectConnection() private readonly connection: Connection,
  ) {
    super();
    this.cls = cls;
    this.storage = this.storageFactory.create('deals');
    this.reportService = new ImportReportService(this.storage);
  }

  protected getEntityModel(): Model<any> {
    return this.dealModel;
  }
  protected getStorage(): ImportStorageService {
    return this.storage;
  }
  protected getReportService(): ImportReportService {
    return this.reportService;
  }
  protected getLockService(): RedisLockService {
    return this.lockService;
  }
  protected getEventEmitter(): EventEmitter2 {
    return this.eventEmitter;
  }
  protected getRedis(): Redis {
    return this.redis;
  }
  protected getConnection(): Connection {
    return this.connection;
  }
  protected getImportJobModel(): Model<any> {
    return this.importJobModel;
  }

  // ΓöÇΓöÇ Row mapping ΓöÇΓöÇ

  protected mapRow(
    raw: Record<string, string>,
    mapping: Record<string, string>,
    row: number,
  ): MappedRow {
    const fields: Record<string, any> = {};
    const arrayFields: Record<string, string[]> = { tags: [] };

    for (const [header, field] of Object.entries(mapping)) {
      const value = (raw[header] ?? '').toString().trim();
      if (!value) continue;

      if (field === 'tags') {
        arrayFields.tags.push(...this.splitMulti(value));
      } else if (field === 'value' || field === 'probability') {
        const num = Number(value);
        if (!isNaN(num)) fields[field] = num;
      } else if (field === 'closeDate') {
        const date = new Date(value);
        if (!isNaN(date.getTime())) fields[field] = date;
      } else if ((SCALAR_FIELDS as readonly string[]).includes(field)) {
        fields[field] = value;
      }
    }

    // Use title as name if name not mapped.
    if (fields.title && !fields.name) {
      fields.name = fields.title;
    }

    arrayFields.tags = this.uniq(arrayFields.tags);

    return { row, fields, arrayFields };
  }

  protected validateRow(
    mapped: MappedRow,
    data: DealImportJobData,
  ): ImportRowError[] {
    return [];
  }

  protected extractDedupValues(
    row: MappedRow,
    field: DedupMatchingField,
  ): string[] {
    switch (field) {
      case 'title':
        return row.fields.title ? [row.fields.title] : [];
      case 'externalId':
        return row.fields.externalId ? [row.fields.externalId] : [];
      default:
        return [];
    }
  }

  protected buildInsert(
    mapped: MappedRow,
    data: DealImportJobData,
    now: Date,
    resolvedRefs: Record<string, string>,
  ): Record<string, any> {
    return {
      ...mapped.fields,
      ...resolvedRefs,
      tags: mapped.arrayFields.tags ?? [],
      pipeline: mapped.fields.pipeline || 'default',
      value: mapped.fields.value ?? 0,
      currency: mapped.fields.currency || 'USD',
      tenantId: data.tenantId,
      createdById: data.userId,
      updatedById: data.userId,
      createdAt: now,
      updatedAt: now,
    };
  }

  protected buildOverwrite(
    mapped: MappedRow,
    data: DealImportJobData,
    resolvedRefs: Record<string, string>,
  ): Record<string, any> {
    const set: Record<string, any> = {
      ...mapped.fields,
      ...resolvedRefs,
      updatedById: data.userId,
      updatedAt: new Date(),
    };
    if ((mapped.arrayFields.tags?.length ?? 0) > 0)
      set.tags = mapped.arrayFields.tags;
    return { $set: set };
  }

  protected buildMerge(
    mapped: MappedRow,
    existing: any,
    data: DealImportJobData,
    _errors: ImportRowError[],
    resolvedRefs: Record<string, string>,
  ): Record<string, any> | null {
    // Deals don't support merge (transactional object).
    // This should never be called because merge is not in dedupPolicies,
    // but implement as a safety net: treat as overwrite.
    return this.buildOverwrite(mapped, data, resolvedRefs);
  }

  // eslint-disable-next-line @typescript-eslint/require-await
  protected async afterBatchWrite(
    affected: Array<{ id?: string; type: 'insert' | 'update'; row: number }>,
    data: DealImportJobData,
  ): Promise<void> {
    for (const a of affected) {
      const event = a.type === 'insert' ? 'record_created' : 'field_updated';
      this.eventEmitter.emit(buildAutomationEventName(event, 'Deal'), {
        tenantId: data.tenantId,
        event,
        object: 'Deal',
        recordId: a.id,
        data: {},
        automationDepth: 0,
      });
    }
  }

  private splitMulti(value: string): string[] {
    return value
      .split(/[,;]/)
      .map((v) => v.trim())
      .filter(Boolean);
  }

  private uniq(values: string[]): string[] {
    return Array.from(new Set(values.filter(Boolean)));
  }
}

import {
  Controller,
  Get,
  Post,
  Patch,
  Delete,
  Param,
  Query,
  Body,
  UploadedFile,
  UseInterceptors,
  HttpCode,
  HttpStatus,
  Logger,
  BadRequestException,
  ForbiddenException,
  PayloadTooLargeException,
} from '@nestjs/common';
import { FileInterceptor } from '@nestjs/platform-express';
import { ClsService } from 'nestjs-cls';

import { FilesService } from './files.service';
import { TenantsService } from '../tenants/tenants.service';
import { ImageProcessingService } from './image-processing.service';
import { RequirePermission } from '../common/permissions';

import {
  UploadFileDto,
  ListFilesQueryDto,
  UpdateFileAccessDto,
  RenameFileDto,
  MoveFileDto,
  BulkMoveDto,
  BulkDeleteDto,
} from './dto/file-management.dto';
import { FileAccessLevel } from './domain/file';
import {
  isAllowedFileName,
  isAllowedMimeType,
  getFileCategory,
  detectMimeFromBuffer,
} from './file-upload-security.util';

import { PutObjectCommand, S3Client } from '@aws-sdk/client-s3';
import { ConfigService } from '@nestjs/config';
import { AllConfigType } from '../config/config.type';
import { randomStringGenerator } from '@nestjs/common/utils/random-string-generator.util';
import * as crypto from 'crypto';

const SAFE_EXT = /^[a-z0-9]{1,8}$/;

/**
 * File Management REST API.
 *
 * Endpoints:
 *   POST   /files/upload             ΓÇö upload a file (multipart)
 *   GET    /files                     ΓÇö list files with ACL filter
 *   GET    /files/:id                 ΓÇö file detail with presigned URL
 *   GET    /files/:id/download        ΓÇö presigned download URL
 *   PATCH  /files/:id/access          ΓÇö update access level
 *   DELETE /files/:id                 ΓÇö soft delete
 *   DELETE /files/:id/purge           ΓÇö hard delete (SUPER_ADMIN)
 *   GET    /storage                   ΓÇö storage usage overview
 */
@Controller({ path: 'files', version: '1' })
export class FileManagementController {
  private readonly logger = new Logger(FileManagementController.name);
  private readonly s3: S3Client;
  private readonly bucket: string;

  constructor(
    private readonly filesService: FilesService,
    private readonly tenantsService: TenantsService,
    private readonly imageProcessingService: ImageProcessingService,
    private readonly configService: ConfigService<AllConfigType>,
    private readonly cls: ClsService,
  ) {
    this.bucket =
      configService.get('file.awsDefaultS3Bucket', { infer: true }) ?? '';
    this.s3 = new S3Client({
      region: configService.get('file.awsS3Region', { infer: true }),
      endpoint:
        configService.get('file.awsS3Endpoint', { infer: true }) || undefined,
      forcePathStyle: !!configService.get('file.awsS3Endpoint', {
        infer: true,
      }),
      credentials: {
        accessKeyId:
          configService.get('file.accessKeyId', { infer: true }) ?? '',
        secretAccessKey:
          configService.get('file.secretAccessKey', { infer: true }) ?? '',
      },
    });
  }

  // ΓöÇΓöÇ Upload ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  @Post('upload')
  @RequirePermission('create', 'files')
  @UseInterceptors(FileInterceptor('file'))
  @HttpCode(HttpStatus.CREATED)
  async uploadFile(
    @UploadedFile() file: Express.Multer.File,
    @Body() dto: UploadFileDto,
  ) {
    const tenantId = this.cls.get<string>('tenantId');
    const userId = this.cls.get<string>('userId');
    if (!tenantId || !userId) {
      throw new BadRequestException('Tenant/User context not found');
    }
    if (!file) {
      throw new BadRequestException('No file provided');
    }

    // ΓöÇΓöÇ Validate ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    if (!isAllowedFileName(file.originalname)) {
      throw new BadRequestException('File type not allowed');
    }
    if (file.mimetype && !isAllowedMimeType(file.mimetype)) {
      throw new BadRequestException(`MIME type ${file.mimetype} not allowed`);
    }

    // HIGH-11: Verify magic bytes match the declared MIME type.
    // Client-supplied Content-Type is trivially forged. An attacker can rename
    // malware.exe ΓåÆ resume.pdf and send Content-Type: application/pdf.
    // The extension check passes, but magic bytes reveal the real format.
    const detectedMime = detectMimeFromBuffer(file.buffer);
    if (detectedMime && !isAllowedMimeType(detectedMime)) {
      throw new BadRequestException(
        `File content does not match an allowed type (detected: ${detectedMime})`,
      );
    }

    const maxFileSize =
      this.configService.get('file.maxFileSize', { infer: true }) || 26214400;
    if (file.size > maxFileSize) {
      throw new PayloadTooLargeException(
        `File size ${(file.size / (1024 * 1024)).toFixed(1)}MB exceeds limit of ${(maxFileSize / (1024 * 1024)).toFixed(0)}MB`,
      );
    }

    // ΓöÇΓöÇ Quota check (atomic) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    const category = dto.category ?? getFileCategory(file.mimetype);
    const countsQuota = category !== 'general';

    if (countsQuota) {
      const withinQuota = await this.tenantsService.incrementStorageUsage(
        tenantId,
        file.size,
      );
      if (!withinQuota) {
        const quota = await this.tenantsService.checkStorageQuota(tenantId);
        throw new PayloadTooLargeException(
          `Storage quota exceeded (${(quota.usedBytes / (1024 * 1024)).toFixed(1)}MB / ${quota.limitBytes === -1 ? 'unlimited' : (quota.limitBytes / (1024 * 1024)).toFixed(0) + 'MB'})`,
        );
      }
    }

    try {
      // ΓöÇΓöÇ Compress if image ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      let uploadBuffer = file.buffer;
      let uploadMimeType = file.mimetype;
      let imageWidth: number | undefined;
      let imageHeight: number | undefined;
      let originalMimeType: string | undefined;
      let originalSize: number | undefined;

      if (this.imageProcessingService.isProcessableImage(file.mimetype)) {
        const compressed = await this.imageProcessingService.compressForStorage(
          file.buffer,
          file.mimetype,
        );
        uploadBuffer = compressed.buffer;
        uploadMimeType = compressed.mimeType;
        imageWidth = compressed.width;
        imageHeight = compressed.height;
        originalMimeType = file.mimetype;
        originalSize = file.size;
      }

      // ΓöÇΓöÇ S3 Upload ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      const ext = (file.originalname.split('.').pop() || '').toLowerCase();
      const safeExt = SAFE_EXT.test(ext) ? ext : 'bin';
      // Use webp extension if compressed to webp
      const finalExt =
        uploadMimeType === 'image/webp' && safeExt !== 'webp'
          ? 'webp'
          : safeExt;
      const storageKey = `${tenantId}/${randomStringGenerator()}.${finalExt}`;

      await this.s3.send(
        new PutObjectCommand({
          Bucket: this.bucket,
          Key: storageKey,
          Body: uploadBuffer,
          ContentType: uploadMimeType,
          ContentDisposition: `attachment; filename="${sanitizeFilename(file.originalname)}"`,
          Metadata: { tenantId },
        }),
      );

      // ΓöÇΓöÇ Thumbnail ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      let thumbnailKey: string | undefined;
      if (this.imageProcessingService.isProcessableImage(file.mimetype)) {
        try {
          const thumbBuffer =
            await this.imageProcessingService.generateThumbnail(file.buffer);
          thumbnailKey = `${tenantId}/thumbs/${randomStringGenerator()}.webp`;
          await this.s3.send(
            new PutObjectCommand({
              Bucket: this.bucket,
              Key: thumbnailKey,
              Body: thumbBuffer,
              ContentType: 'image/webp',
              Metadata: { tenantId },
            }),
          );
        } catch (err) {
          this.logger.warn(
            `Thumbnail generation failed: ${(err as Error).message}`,
          );
        }
      }

      // ΓöÇΓöÇ Checksum ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      const checksum = crypto
        .createHash('sha256')
        .update(uploadBuffer)
        .digest('hex');

      // ΓöÇΓöÇ DB Record ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      const fileRecord = await this.filesService.upsertByMessageId(
        tenantId,
        `upload_${storageKey}`, // unique key for uploads
        {
          path: storageKey,
          fileName: file.originalname,
          mimeType: uploadMimeType,
          fileSize: uploadBuffer.length,
          checksum,
          category,
          source: 'upload',
          status: 'ready',
          uploadedBy: userId,
          accessLevel: dto.accessLevel ?? 'tenant',
          allowedUserIds: [],
          conversationId: dto.conversationId,
          folderId: dto.folderId ?? undefined,
          thumbnailKey,
          imageMetadata:
            imageWidth || imageHeight
              ? {
                  width: imageWidth,
                  height: imageHeight,
                  originalMimeType,
                  originalSize,
                }
              : undefined,
          tags: dto.tags ?? [],
          isDeleted: false,
        },
      );

      this.logger.log(
        `File uploaded: ${storageKey} (${(uploadBuffer.length / 1024).toFixed(0)}KB) by user ${userId}`,
      );

      return { file: fileRecord.file };
    } catch (err) {
      // Rollback quota on failure
      if (countsQuota) {
        await this.tenantsService
          .decrementStorageUsage(tenantId, file.size)
          .catch((e) =>
            this.logger.warn(`Quota rollback failed: ${(e as Error).message}`),
          );
      }
      throw err;
    }
  }

  // ΓöÇΓöÇ List ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  @Get()
  @RequirePermission('view', 'files')
  async listFiles(@Query() query: ListFilesQueryDto) {
    const tenantId = this.cls.get<string>('tenantId');
    const userId = this.cls.get<string>('userId');
    const userRole = this.cls.get<string>('tenantRole') ?? '';

    return this.filesService.listFiles(
      tenantId,
      userId,
      userRole,
      {
        category: query.category,
        mimeTypePrefix: query.type,
        search: query.search,
        folderId: query.folderId === 'root' ? null : query.folderId,
      },
      { page: query.page ?? 1, limit: query.limit ?? 20 },
    );
  }

  // ΓöÇΓöÇ Detail ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  @Get(':id')
  @RequirePermission('view', 'files')
  async getFile(@Param('id') id: string) {
    const userId = this.cls.get<string>('userId');
    const userRole = this.cls.get<string>('tenantRole') ?? '';

    const file = await this.filesService.findById(id);
    if (!file) throw new BadRequestException('File not found');
    if (!this.filesService.checkAccess(file, userId, userRole)) {
      throw new ForbiddenException('No access to this file');
    }

    const downloadUrl = await this.filesService.getPresignedDownloadUrl(
      file.path,
    );
    const thumbnailUrl = file.thumbnailKey
      ? await this.filesService.getPresignedDownloadUrl(file.thumbnailKey)
      : undefined;

    return {
      ...file,
      path: undefined, // Never expose storageKey
      downloadUrl,
      thumbnailUrl,
    };
  }

  // ΓöÇΓöÇ Download URL ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  @Get(':id/download')
  @RequirePermission('view', 'files')
  async getDownloadUrl(@Param('id') id: string) {
    const userId = this.cls.get<string>('userId');
    const userRole = this.cls.get<string>('tenantRole') ?? '';

    const file = await this.filesService.findById(id);
    if (!file) throw new BadRequestException('File not found');
    if (!this.filesService.checkAccess(file, userId, userRole)) {
      throw new ForbiddenException('No access to this file');
    }

    const url = await this.filesService.getPresignedDownloadUrl(file.path);
    return { url, expiresIn: 3600 };
  }

  // ΓöÇΓöÇ Update Access ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  @Patch(':id/access')
  @RequirePermission('edit', 'files')
  @HttpCode(HttpStatus.OK)
  async updateAccess(
    @Param('id') id: string,
    @Body() dto: UpdateFileAccessDto,
  ) {
    const userId = this.cls.get<string>('userId');
    const userRole = this.cls.get<string>('tenantRole') ?? '';

    return this.filesService.updateAccessLevel(
      id,
      userId,
      userRole,
      dto.accessLevel,
      dto.allowedUserIds ?? [],
    );
  }

  // ΓöÇΓöÇ Soft Delete ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  @Delete(':id')
  @RequirePermission('delete', 'files')
  @HttpCode(HttpStatus.OK)
  async softDeleteFile(@Param('id') id: string) {
    const userId = this.cls.get<string>('userId');
    const userRole = this.cls.get<string>('tenantRole') ?? '';

    return this.filesService.softDelete(id, userId, userRole);
  }

  // ΓöÇΓöÇ Hard Delete (SUPER_ADMIN) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  @Delete(':id/purge')
  @HttpCode(HttpStatus.OK)
  async hardDeleteFile(@Param('id') id: string) {
    const userRole = this.cls.get<string>('tenantRole') ?? '';
    const tenantId = this.cls.get<string>('tenantId');

    if (!['OWNER'].includes(userRole?.toUpperCase())) {
      throw new ForbiddenException('Only OWNER can permanently delete files');
    }

    const { fileSize } = await this.filesService.hardDelete(id);

    // Decrement quota
    if (fileSize > 0) {
      await this.tenantsService.decrementStorageUsage(tenantId, fileSize);
    }

    return { deleted: true, freedBytes: fileSize };
  }

  // ΓöÇΓöÇ Storage Overview ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  @Get('/storage/usage')
  @RequirePermission('view', 'storage')
  async getStorageUsage() {
    const tenantId = this.cls.get<string>('tenantId');
    const result = await this.tenantsService.getStorageBreakdown(tenantId);

    const [
      topFiles,
      totalFilesCount,
      recentUploadsCount,
      actualUsedBytes,
      categoryBreakdown,
    ] = await Promise.all([
      this.filesService.getTopFiles(tenantId, 10),
      this.filesService.countFiles(tenantId),
      this.filesService.countRecentUploads(tenantId, 7),
      this.filesService.sumFileSizes(tenantId),
      this.filesService.getCategoryBreakdown(tenantId),
    ]);

    const limitBytes = result.quota.limitBytes;

    return {
      quota: {
        limitBytes,
        usedBytes: actualUsedBytes,
        usagePercent:
          limitBytes > 0 && limitBytes !== -1
            ? Math.round((actualUsedBytes / limitBytes) * 100)
            : 0,
        unlimited: limitBytes === -1,
        limitMB:
          limitBytes === -1 ? -1 : Math.round(limitBytes / (1024 * 1024)),
        usedMB: Math.round(actualUsedBytes / (1024 * 1024)),
      },
      breakdown: categoryBreakdown,
      topFiles: topFiles.map((f) => ({
        id: f.id,
        fileName: f.fileName,
        mimeType: f.mimeType,
        fileSize: f.fileSize,
        category: f.category,
        createdAt: f.createdAt,
      })),
      totalFilesCount,
      recentUploadsCount,
    };
  }

  // ΓöÇΓöÇ Cloud Drive Extensions ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  @Patch(':id/rename')
  @RequirePermission('edit', 'files')
  @HttpCode(HttpStatus.OK)
  async renameFile(@Param('id') id: string, @Body() dto: RenameFileDto) {
    const userId = this.cls.get<string>('userId');
    const userRole = this.cls.get<string>('tenantRole') ?? '';
    return this.filesService.renameFile(id, userId, userRole, dto.name);
  }

  @Patch(':id/move')
  @RequirePermission('edit', 'files')
  @HttpCode(HttpStatus.OK)
  async moveFile(@Param('id') id: string, @Body() dto: MoveFileDto) {
    const userId = this.cls.get<string>('userId');
    const userRole = this.cls.get<string>('tenantRole') ?? '';
    return this.filesService.moveFile(
      id,
      userId,
      userRole,
      dto.folderId ?? null,
    );
  }

  @Post('bulk/move')
  @RequirePermission('edit', 'files')
  @HttpCode(HttpStatus.OK)
  async bulkMove(@Body() dto: BulkMoveDto) {
    const tenantId = this.cls.get<string>('tenantId');
    const count = await this.filesService.bulkMove(
      tenantId,
      dto.fileIds,
      dto.folderId ?? null,
    );
    return { movedCount: count };
  }

  @Post('bulk/delete')
  @RequirePermission('delete', 'files')
  @HttpCode(HttpStatus.OK)
  async bulkDelete(@Body() dto: BulkDeleteDto) {
    const tenantId = this.cls.get<string>('tenantId');
    const userId = this.cls.get<string>('userId');
    const userRole = this.cls.get<string>('tenantRole') ?? '';
    const count = await this.filesService.bulkDelete(
      tenantId,
      userId,
      userRole,
      dto.fileIds,
    );
    return { deletedCount: count };
  }

  @Post(':id/restore')
  @RequirePermission('edit', 'files')
  @HttpCode(HttpStatus.OK)
  async restoreFile(@Param('id') id: string) {
    const userId = this.cls.get<string>('userId');
    const userRole = this.cls.get<string>('tenantRole') ?? '';
    return this.filesService.restoreFile(id, userId, userRole);
  }

  @Get('trash')
  @RequirePermission('view', 'files')
  async listTrash(
    @Query('page') page?: number,
    @Query('limit') limit?: number,
  ) {
    const tenantId = this.cls.get<string>('tenantId');
    return this.filesService.listTrash(tenantId, {
      page: page ?? 1,
      limit: limit ?? 20,
    });
  }

  @Get('search')
  @RequirePermission('view', 'files')
  async searchFiles(
    @Query('q') q?: string,
    @Query('page') page?: number,
    @Query('limit') limit?: number,
  ) {
    const tenantId = this.cls.get<string>('tenantId');
    const userId = this.cls.get<string>('userId');
    const userRole = this.cls.get<string>('tenantRole') ?? '';

    return this.filesService.listFiles(
      tenantId,
      userId,
      userRole,
      { search: q },
      { page: page ?? 1, limit: limit ?? 20 },
    );
  }
}

function sanitizeFilename(name: string): string {
  return (
    name
      .replace(/[\r\n"\\]/g, '_')
      .replace(/[^\w.\-]/g, '_')
      .slice(0, 120) || 'file'
  );
}

import {
  Injectable,
  Logger,
  NotFoundException,
  ForbiddenException,
  PayloadTooLargeException,
} from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { ClsService } from 'nestjs-cls';
import {
  S3Client,
  DeleteObjectCommand,
  GetObjectCommand,
} from '@aws-sdk/client-s3';
import { getSignedUrl } from '@aws-sdk/s3-request-presigner';

import {
  FileRepository,
  PaginatedResult,
  PaginationOptions,
  FileListFilters,
} from './infrastructure/persistence/file.repository';
import {
  FileType,
  FileAccessLevel,
  FileCategory,
  FileStatus,
} from './domain/file';
import { NullableType } from '../utils/types/nullable.type';
import { AllConfigType } from '../config/config.type';

@Injectable()
export class FilesService {
  private readonly logger = new Logger(FilesService.name);
  private readonly s3: S3Client;
  private readonly bucket: string;

  constructor(
    private readonly fileRepository: FileRepository,
    private readonly configService: ConfigService<AllConfigType>,
    private readonly cls: ClsService,
  ) {
    this.bucket =
      configService.get('file.awsDefaultS3Bucket', { infer: true }) ?? '';
    this.s3 = new S3Client({
      region: configService.get('file.awsS3Region', { infer: true }),
      endpoint:
        configService.get('file.awsS3Endpoint', { infer: true }) || undefined,
      forcePathStyle: !!configService.get('file.awsS3Endpoint', {
        infer: true,
      }),
      credentials: {
        accessKeyId:
          configService.get('file.accessKeyId', { infer: true }) ?? '',
        secretAccessKey:
          configService.get('file.secretAccessKey', { infer: true }) ?? '',
      },
    });
  }

  // ΓöÇΓöÇ Basic CRUD ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  findById(id: FileType['id']): Promise<NullableType<FileType>> {
    return this.fileRepository.findById(id);
  }

  findByIds(ids: FileType['id'][]): Promise<FileType[]> {
    return this.fileRepository.findByIds(ids);
  }

  // ΓöÇΓöÇ Access Control ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  /**
   * Check if a user has access to a file.
   * OWNER/ADMIN bypass all ACL. Otherwise:
   * - tenant: all tenant members
   * - private: only uploadedBy or allowedUserIds
   * - public: everyone
   */
  checkAccess(file: FileType, userId: string, userRole: string): boolean {
    if (!file) return false;
    if (file.isDeleted && file.status === 'deleted') return false;

    // OWNER/ADMIN bypass
    if (['OWNER', 'ADMIN'].includes(userRole?.toUpperCase())) return true;

    if (file.accessLevel === 'public') return true;
    if (file.accessLevel === 'tenant') return true; // Tenant guard already filters by tenantId

    // private: only owner or explicitly allowed users
    if (file.accessLevel === 'private') {
      if (file.uploadedBy === userId) return true;
      if (file.allowedUserIds?.includes(userId)) return true;
      return false;
    }

    return false;
  }

  // ΓöÇΓöÇ Presigned Download URL ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  /**
   * Generate a presigned download URL for a file.
   * ACL must be checked BEFORE calling this method.
   * URL is never cached in DB ΓÇö always generated fresh.
   */
  async getPresignedDownloadUrl(
    storageKey: string,
    ttlSeconds = 3600,
  ): Promise<string> {
    const command = new GetObjectCommand({
      Bucket: this.bucket,
      Key: storageKey,
    });
    return getSignedUrl(this.s3, command, { expiresIn: ttlSeconds });
  }

  // ΓöÇΓöÇ Listing ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  async listFiles(
    tenantId: string,
    userId: string,
    userRole: string,
    filters?: FileListFilters,
    pagination?: PaginationOptions,
  ): Promise<PaginatedResult<FileType>> {
    return this.fileRepository.findByTenant(
      tenantId,
      userId,
      userRole,
      filters,
      pagination,
    );
  }

  async listConversationFiles(
    tenantId: string,
    conversationId: string,
    filters?: { mimeTypePrefix?: string },
    pagination?: PaginationOptions,
  ): Promise<PaginatedResult<FileType>> {
    return this.fileRepository.findByConversation(
      tenantId,
      conversationId,
      filters,
      pagination,
    );
  }

  // ΓöÇΓöÇ Soft Delete ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  async softDelete(
    fileId: string,
    userId: string,
    userRole: string,
  ): Promise<FileType> {
    const file = await this.fileRepository.findById(fileId);
    if (!file) throw new NotFoundException('File not found');
    if (!this.checkAccess(file, userId, userRole)) {
      throw new ForbiddenException('No access to this file');
    }
    // Only owner or admin can delete
    if (
      file.uploadedBy !== userId &&
      !['OWNER', 'ADMIN'].includes(userRole?.toUpperCase())
    ) {
      throw new ForbiddenException('Only file owner or admin can delete');
    }
    const deleted = await this.fileRepository.softDelete(fileId);
    if (!deleted) throw new NotFoundException('File not found');
    return deleted;
  }

  // ΓöÇΓöÇ Hard Delete (SUPER_ADMIN only) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  /**
   * Permanently delete file from S3 + DB. Returns fileSize for quota decrement.
   */
  async hardDelete(fileId: string): Promise<{ fileSize: number }> {
    const file = await this.fileRepository.findById(fileId);
    if (!file) throw new NotFoundException('File not found');

    // Delete from S3
    try {
      await this.s3.send(
        new DeleteObjectCommand({ Bucket: this.bucket, Key: file.path }),
      );
      // Also delete thumbnail if exists
      if (file.thumbnailKey) {
        await this.s3.send(
          new DeleteObjectCommand({
            Bucket: this.bucket,
            Key: file.thumbnailKey,
          }),
        );
      }
    } catch (err) {
      this.logger.warn(
        `S3 delete failed for ${file.path}: ${(err as Error).message}`,
      );
    }

    // Delete DB record
    await this.fileRepository.hardDelete(fileId);

    return { fileSize: file.fileSize ?? 0 };
  }

  // ΓöÇΓöÇ ACL Update ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  async updateAccessLevel(
    fileId: string,
    userId: string,
    userRole: string,
    accessLevel: FileAccessLevel,
    allowedUserIds: string[],
  ): Promise<FileType> {
    const file = await this.fileRepository.findById(fileId);
    if (!file) throw new NotFoundException('File not found');

    // Only owner or admin can change access
    if (
      file.uploadedBy !== userId &&
      !['OWNER', 'ADMIN'].includes(userRole?.toUpperCase())
    ) {
      throw new ForbiddenException(
        'Only file owner or admin can change access',
      );
    }

    const updated = await this.fileRepository.updateAccessLevel(
      fileId,
      accessLevel,
      allowedUserIds,
    );
    if (!updated) throw new NotFoundException('File not found');
    return updated;
  }

  // ΓöÇΓöÇ Status Update ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  async updateStatus(
    fileId: string,
    status: FileStatus,
  ): Promise<NullableType<FileType>> {
    return this.fileRepository.updateStatus(fileId, status);
  }

  // ΓöÇΓöÇ Upsert (Omni media dedup) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  async upsertByMessageId(
    tenantId: string,
    messageId: string,
    data: Partial<FileType>,
  ): Promise<{ file: FileType; isNew: boolean }> {
    return this.fileRepository.upsertByMessageId(tenantId, messageId, data);
  }

  // ΓöÇΓöÇ Cloud Drive Extensions ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  async renameFile(
    fileId: string,
    userId: string,
    userRole: string,
    newName: string,
  ): Promise<FileType> {
    const file = await this.fileRepository.findById(fileId);
    if (!file) throw new NotFoundException('File not found');
    if (!this.checkAccess(file, userId, userRole)) {
      throw new ForbiddenException('No access to this file');
    }
    if (
      file.uploadedBy !== userId &&
      !['OWNER', 'ADMIN'].includes(userRole?.toUpperCase())
    ) {
      throw new ForbiddenException('Only file owner or admin can rename');
    }

    const trimmed = newName.trim();
    if (!trimmed || trimmed.length > 255) {
      throw new NotFoundException('File name must be 1-255 characters');
    }

    const renamed = await this.fileRepository.rename(fileId, trimmed);
    if (!renamed) throw new NotFoundException('File not found');
    return renamed;
  }

  async moveFile(
    fileId: string,
    userId: string,
    userRole: string,
    folderId: string | null,
  ): Promise<FileType> {
    const file = await this.fileRepository.findById(fileId);
    if (!file) throw new NotFoundException('File not found');
    if (!this.checkAccess(file, userId, userRole)) {
      throw new ForbiddenException('No access to this file');
    }

    const moved = await this.fileRepository.moveToFolder(fileId, folderId);
    if (!moved) throw new NotFoundException('File not found');
    return moved;
  }

  async bulkMove(
    tenantId: string,
    fileIds: string[],
    folderId: string | null,
  ): Promise<number> {
    if (!fileIds.length) return 0;
    return this.fileRepository.bulkMoveToFolder(fileIds, folderId);
  }

  async bulkDelete(
    tenantId: string,
    userId: string,
    userRole: string,
    fileIds: string[],
  ): Promise<number> {
    if (!fileIds.length) return 0;
    return this.fileRepository.bulkSoftDelete(fileIds);
  }

  async restoreFile(
    fileId: string,
    userId: string,
    userRole: string,
  ): Promise<FileType> {
    const file = await this.fileRepository.findById(fileId);
    if (!file) throw new NotFoundException('File not found');
    if (
      file.uploadedBy !== userId &&
      !['OWNER', 'ADMIN'].includes(userRole?.toUpperCase())
    ) {
      throw new ForbiddenException('Only file owner or admin can restore');
    }

    const restored = await this.fileRepository.restore(fileId);
    if (!restored) throw new NotFoundException('File not found');
    return restored;
  }

  async listTrash(
    tenantId: string,
    pagination?: { page: number; limit: number },
  ) {
    return this.fileRepository.findTrashed(tenantId, pagination);
  }

  async getTopFiles(tenantId: string, limit = 10) {
    return this.fileRepository.findTopBySize(tenantId, limit);
  }

  async countFiles(tenantId: string) {
    return this.fileRepository.countByTenant(tenantId);
  }

  async countRecentUploads(tenantId: string, days = 7) {
    const since = new Date();
    since.setDate(since.getDate() - days);
    return this.fileRepository.countRecentUploads(tenantId, since);
  }

  async sumFileSizes(tenantId: string): Promise<number> {
    return this.fileRepository.sumFileSizes(tenantId);
  }

  async getCategoryBreakdown(
    tenantId: string,
  ): Promise<Record<string, { count: number; sizeBytes: number }>> {
    return this.fileRepository.getCategoryBreakdown(tenantId);
  }
}

import { Injectable, Logger } from '@nestjs/common';
import { createHmac, timingSafeEqual } from 'crypto';
import { ChannelAdapter } from './channel-adapter.interface';
import { OmniPayload, ChannelType, MessageType } from '../domain/omni-payload';

/**
 * Deterministic JSON serializer. Sorts object keys recursively so two payloads
 * with identical content but different key insertion orders produce identical
 * bytes ΓÇö necessary for HMAC signature verification to be stable.
 */
function stringifyCanonical(value: any): string {
  if (value === null || typeof value !== 'object') {
    return JSON.stringify(value);
  }
  if (Array.isArray(value)) {
    return '[' + value.map((v) => stringifyCanonical(v)).join(',') + ']';
  }
  const keys = Object.keys(value).sort();
  return (
    '{' +
    keys
      .map((k) => JSON.stringify(k) + ':' + stringifyCanonical(value[k]))
      .join(',') +
    '}'
  );
}

/**
 * Zalo OA webhook ΓåÆ OmniPayload adapter.
 *
 * Reference: https://developers.zalo.me/docs/official-account/webhook
 *
 * Incoming shape (simplified):
 * {
 *   app_id: '<APP_ID>',
 *   sender: { id: '<USER_ID>' },
 *   recipient: { id: '<OA_ID>' },
 *   event_name: 'user_send_text' | 'user_send_image' | 'user_send_file' | ΓÇª,
 *   message: {
 *     msg_id: '<MSG_ID>',
 *     text?: 'Hello',
 *     attachments?: [{ type, payload: { url, thumbnail?, name?, size? } }]
 *   },
 *   timestamp: '1234567890000'
 * }
 *
 * ΓÜá∩╕Å  Zalo media URLs EXPIRE after ~30 minutes.  The media proxy service
 *     must download and cache them before they become invalid.
 */
@Injectable()
export class ZaloAdapter implements ChannelAdapter {
  readonly channelType: ChannelType = 'zalo';
  private readonly logger = new Logger(ZaloAdapter.name);

  normalize(
    rawPayload: any,
    tenantId: string,
    channelId: string,
    channelConfig?: any,
  ): OmniPayload {
    const messageType = this.resolveMessageType(
      rawPayload.event_name,
      rawPayload.message,
    );
    const mediaUrl = this.extractMediaUrl(rawPayload.message);

    return {
      tenantId,
      channelId,
      channelAccount: rawPayload.recipient?.id,
      channelType: this.channelType,
      senderId: rawPayload.sender.id,
      senderType: 'customer',
      messageType,
      content: rawPayload.message?.text ?? '',
      mediaUrl: mediaUrl ?? undefined,
      metadata: {
        appId: rawPayload.app_id,
        eventName: rawPayload.event_name,
        oaId: rawPayload.recipient?.id,
        // Keep raw attachment metadata for the media proxy
        attachmentMeta: rawPayload.message?.attachments?.[0]?.payload,
        bot: this.resolveBotConfig(channelConfig),
      },
      externalMessageId: rawPayload.message?.msg_id ?? '',
      externalConversationId: `${rawPayload.sender.id}_${rawPayload.recipient?.id}`,
      timestamp: new Date(Number(rawPayload.timestamp)),
      providerTimestamp: new Date(Number(rawPayload.timestamp)),
    };
  }

  /**
   * Verify the Zalo webhook MAC signature.
   *
   * Zalo OA signs webhook payloads using HMAC-SHA256 with the OA Secret Key.
   * The `mac` field in the body contains the computed signature.
   *
   * @see https://developers.zalo.me/docs/official-account/webhook/webhook-security
   */
  validateWebhook(
    headers: Record<string, string>,
    body: any,
    _rawBody?: Buffer,
  ): boolean {
    void headers;
    void _rawBody;
    const mac = body?.mac;
    if (!mac) {
      this.logger.warn('Zalo webhook missing mac field');
      return false;
    }

    const oaSecretKey =
      process.env.ZALO_OA_SECRET_KEY || process.env.ZALO_WEBHOOK_SECRET;
    if (!oaSecretKey) {
      this.logger.error(
        'ZALO_OA_SECRET_KEY is not configured ΓÇö cannot verify Zalo webhook',
      );
      return false;
    }

    // Zalo MAC is computed over specific payload fields (excluding the `mac` field itself).
    // Use a canonical (sorted-key) JSON serializer so the signature is stable
    // regardless of how the JSON parser ordered keys.
    const { mac: _mac, ...payloadWithoutMac } = body;
    const dataToSign = stringifyCanonical(payloadWithoutMac);
    const expectedMac = createHmac('sha256', oaSecretKey)
      .update(dataToSign)
      .digest('hex');

    try {
      return timingSafeEqual(Buffer.from(mac), Buffer.from(expectedMac));
    } catch {
      return false;
    }
  }

  private resolveMessageType(eventName: string, message: any): MessageType {
    switch (eventName) {
      case 'user_send_text':
        return 'text';
      case 'user_send_image':
        return 'image';
      case 'user_send_file':
        return 'file';
      case 'user_send_audio':
        return 'audio';
      case 'user_send_video':
        return 'video';
      case 'user_send_sticker':
        return 'sticker';
      case 'user_send_location':
        return 'location';
      default:
        // Fallback: sniff from attachment type
        return this.sniffFromAttachment(message) ?? 'text';
    }
  }

  private sniffFromAttachment(message: any): MessageType | null {
    const attachment = message?.attachments?.[0];
    if (!attachment) return null;
    const typeMap: Record<string, MessageType> = {
      image: 'image',
      file: 'file',
      audio: 'audio',
      video: 'video',
      sticker: 'sticker',
    };
    return typeMap[attachment.type] ?? 'file';
  }

  private extractMediaUrl(message: any): string | null {
    const attachment = message?.attachments?.[0];
    return attachment?.payload?.url ?? attachment?.payload?.thumbnail ?? null;
  }

  private resolveBotConfig(
    channelConfig?: any,
  ): Record<string, any> | undefined {
    const config = channelConfig?.config ?? {};
    return config.bot ?? config.typebot ?? undefined;
  }

  send(
    recipientId: string,
    content: string,
    messageType: string,
    channelConfig: any,
  ): Promise<any> {
    // HIGH-08: Fail loudly instead of returning a fake success.
    throw new Error(
      `Zalo OA API send not implemented ΓÇö cannot deliver ${messageType} to ${recipientId}`,
    );
  }
}

import { Processor } from '@nestjs/bullmq';
import { Job } from 'bullmq';
import { Logger } from '@nestjs/common';
import { EventEmitter2 } from '@nestjs/event-emitter';
import { ClsService } from 'nestjs-cls';
import {
  BaseTenantConsumer,
  TenantJobData,
} from '../../queue/base-tenant.consumer';
import { OmniPayload } from '../domain/omni-payload';
import { OMNI_ROUTING_QUEUE } from './omni-queue.constants';
import { RedisService } from '../../redis/redis.service';

export type OmniRoutingJobData = OmniPayload;

/** 24-hour window to deduplicate retried BullMQ jobs by externalMessageId. */
const OMNI_DEDUP_TTL_SECONDS = 86_400;

@Processor(OMNI_ROUTING_QUEUE)
export class OmniRoutingProcessor extends BaseTenantConsumer<OmniRoutingJobData> {
  protected readonly logger = new Logger(OmniRoutingProcessor.name);
  protected readonly cls: ClsService;

  constructor(
    private readonly eventEmitter: EventEmitter2,
    cls: ClsService,
    private readonly redisService: RedisService,
  ) {
    super();
    this.cls = cls;
  }

  protected async handle(job: Job<OmniRoutingJobData>): Promise<void> {
    const payload = job.data;

    const dedupKey = `omni:dedup:${payload.tenantId}:${payload.externalMessageId}`;
    const client = this.redisService.getClient();
    const acquired = await client.set(
      dedupKey,
      '1',
      'EX',
      OMNI_DEDUP_TTL_SECONDS,
      'NX',
    );

    if (!acquired) {
      this.logger.log(
        `[OmniRouting] Duplicate skipped: externalMessageId=${payload.externalMessageId} tenant=${payload.tenantId}`,
      );
      return;
    }

    this.logger.log(
      `Routing omni message ${payload.externalMessageId} for tenant ${payload.tenantId}`,
    );

    // CRIT-07: Roll back the dedup key on failure so BullMQ retries can
    // re-process the message. Without this, a transient downstream failure
    // permanently suppresses the message for the 24h TTL window.
    try {
      await this.eventEmitter.emitAsync('omni.message.received', payload);
    } catch (error) {
      await client.del(dedupKey).catch(() => undefined);
      throw error;
    }
  }
}

import { NotFoundException } from '@nestjs/common';
import { WebhookProcessor, WebhookJobData } from './webhook-processor';

/**
 * WebhookProcessor ΓÇö Phase 2 comprehensive tests
 *
 * Existing tests cover basic dedup and key scoping.
 * These tests cover:
 * - E11000 swallowing (Mongo duplicate key during processing ΓåÆ ack, don't retry)
 * - NotFoundException swallowing (channel deleted ΓåÆ ack, don't retry)
 * - Redis lock cleanup on unexpected errors
 * - VIP sender detection
 * - Pre-resolved channel data path
 * - Provider message ID extraction across channel types
 * - No-dedup when provider message ID is missing
 */
describe('WebhookProcessor ΓÇö error handling & edge cases', () => {
  let processor: WebhookProcessor;
  let processorService: { process: jest.Mock };
  let channelsService: { findAnyByAccount: jest.Mock };
  let contactRepo: { isVIPSender: jest.Mock };
  let cls: { runWith: jest.Mock };
  let redis: { set: jest.Mock; del: jest.Mock };

  beforeEach(() => {
    processorService = { process: jest.fn().mockResolvedValue(undefined) };
    channelsService = {
      findAnyByAccount: jest.fn().mockResolvedValue({
        id: 'channel_1',
        tenantId: 'tenant_1',
      }),
    };
    contactRepo = { isVIPSender: jest.fn().mockResolvedValue(false) };
    cls = { runWith: jest.fn((_context, callback) => callback()) };
    redis = {
      set: jest.fn().mockResolvedValue('OK'),
      del: jest.fn().mockResolvedValue(1),
    };

    processor = new WebhookProcessor(
      processorService as any,
      channelsService as any,
      contactRepo as any,
      cls as any,
      redis as any,
    );
  });

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // E11000 ΓÇö Mongo duplicate key ΓåÆ swallow, don't retry
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  describe('MongoDB duplicate key (E11000)', () => {
    it('should swallow E11000 and not throw (prevents BullMQ retry)', async () => {
      const e11000 = new Error('E11000 duplicate key');
      (e11000 as any).code = 11000;
      processorService.process.mockRejectedValueOnce(e11000);

      // Should NOT throw ΓÇö BullMQ interprets throw as "retry"
      await expect(
        processor.process(createFacebookJob()),
      ).resolves.toBeUndefined();
    });

    it('should NOT release Redis lock on E11000 (message was already persisted)', async () => {
      const e11000 = new Error('E11000');
      (e11000 as any).code = 11000;
      processorService.process.mockRejectedValueOnce(e11000);

      await processor.process(createFacebookJob());

      // del should NOT be called ΓÇö the idempotency lock should remain
      // since the message was successfully persisted by the other process
      expect(redis.del).not.toHaveBeenCalled();
    });
  });

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // NotFoundException ΓÇö channel deleted ΓåÆ swallow, don't retry
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  describe('NotFoundException (channel deleted)', () => {
    it('should swallow NotFoundException and not throw', async () => {
      channelsService.findAnyByAccount.mockRejectedValueOnce(
        new NotFoundException('Channel not found'),
      );

      await expect(
        processor.process(createFacebookJob()),
      ).resolves.toBeUndefined();
    });

    it('should not process the message when channel is not found', async () => {
      channelsService.findAnyByAccount.mockRejectedValueOnce(
        new NotFoundException('Channel deleted'),
      );

      await processor.process(createFacebookJob());

      expect(processorService.process).not.toHaveBeenCalled();
    });
  });

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // Unexpected errors ΓÇö release Redis lock, re-throw for retry
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  describe('unexpected errors', () => {
    it('should re-throw unexpected errors for BullMQ retry', async () => {
      processorService.process.mockRejectedValueOnce(
        new Error('Adapter timeout'),
      );

      await expect(processor.process(createFacebookJob())).rejects.toThrow(
        'Adapter timeout',
      );
    });

    it('should release Redis lock on unexpected error (allows retry dedup)', async () => {
      processorService.process.mockRejectedValueOnce(
        new Error('Network error'),
      );

      try {
        await processor.process(createFacebookJob());
      } catch {}

      // Redis del should be called to release the lock
      expect(redis.del).toHaveBeenCalledWith(
        'processed:webhook:facebook:page_1:mid.1',
      );
    });
  });

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
