};

@Processor(TENANT_PROVISIONING_QUEUE)
export class TenantProvisioningWorker
  extends WorkerHost
  implements OnModuleDestroy
{
  private readonly logger = new Logger(TenantProvisioningWorker.name);
  /**
   * Provisioning jobs run a multi-step saga (Keycloak + Mongo + bot
   * workspace) that can take 30s+. We hold a reference to each in-flight
   * job so SIGTERM can drain them instead of leaving half-provisioned
   * tenants in PROVISIONING status.
   */
  private readonly inFlight = new Set<Promise<unknown>>();
  private destroying = false;

  constructor(
    private readonly tenantsRepository: TenantsRepository,
    private readonly aliasReservationRepository: TenantAliasReservationRepository,
    private readonly provisioningJobRepository: ProvisioningJobRepository,
    private readonly keycloakAdminService: KeycloakAdminService,
    private readonly userRepository: UserRepository,
    private readonly redisService: RedisService,
    private readonly crmBotWorkspaceProvisioningService: CrmBotWorkspaceProvisioningService,
    private readonly eventEmitter: EventEmitter2,
    private readonly configService: ConfigService<AllConfigType>,
    private readonly cls: ClsService,
    private readonly transactionManager: TransactionManager,
  ) {
    super();
  }

  // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  // Main job handler
  // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  async process(job: Job<TenantProvisioningJobData>): Promise<void> {
    const task = this.runJob(job);
    this.inFlight.add(task);
    task.finally(() => this.inFlight.delete(task));
    return task;
  }

  async onModuleDestroy(): Promise<void> {
    if (this.destroying) return;
    this.destroying = true;
    if (this.inFlight.size > 0) {
      this.logger.log(
        `[TenantProvisioningWorker] Waiting for ${this.inFlight.size} in-flight job(s) to finishΓÇª`,
      );
      // 25s drain budget ΓÇö long enough for the saga to either commit step N
      // or trigger compensating rollbacks. After that k8s will SIGKILL.
      await Promise.race([
        Promise.allSettled(Array.from(this.inFlight)),
        new Promise((resolve) => setTimeout(resolve, 25_000).unref()),
      ]);
    }
    // BullMQ WorkerHost exposes a `worker` instance ΓÇö close it so it stops
    // pulling new jobs while we wait for the drain above.
    try {
      await (this as any).worker?.close?.();
    } catch {
      /* ignore */
    }
    this.logger.log('[TenantProvisioningWorker] Drained');
  }

  private async runJob(job: Job<TenantProvisioningJobData>): Promise<void> {
    const data = job.data;
    const { provisioningId, source } = data;

    this.logger.log(
      `[${source}] Processing provisioning job ${provisioningId} for "${data.companyName}"`,
    );

    // ΓöÇΓöÇ Saga compensation trackers ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
    let aliasReserved = false;
    let keycloakOrgId: string | null = null;
    let keycloakUserCreatedByThisJob = false;
    let keycloakUserId: string | null = null;
    let tenantId: string | null = null;

    try {
      await this.updateStatus(provisioningId, {
        status: 'PROVISIONING',
        currentStep: 0,
        totalSteps: TOTAL_STEPS,
        stepLabel: 'StartingΓÇª',
      });

      // ΓöÇΓöÇ Step 1: Alias already reserved by ensureUniqueAlias (producer) ΓöÇΓöÇ
      // Verify reservation exists
      aliasReserved = true;
      await this.reportStep(provisioningId, 1);

      // ΓöÇΓöÇ Step 2: Create Keycloak Organization ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      const kcOrg = await this.keycloakAdminService.createOrganization(
        data.companyName,
        data.alias,
      );
      keycloakOrgId = kcOrg.id;
      await this.reportStep(provisioningId, 2);

      // ΓöÇΓöÇ Step 3: Find or create the Keycloak User ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      let kcUser = await this.keycloakAdminService.findUserByEmail(data.email);
      if (kcUser) {
        keycloakUserId = kcUser.id;
        this.logger.log(`Reusing existing KC user ${keycloakUserId}`);
      } else {
        // PLG: password is provided; SLG: create without password
        const password = data.password || this.generateTempPassword();
        kcUser = await this.keycloakAdminService.createUser(
          data.email,
          password,
          data.fullName,
        );
        keycloakUserId = kcUser.id;
        keycloakUserCreatedByThisJob = true;
        this.logger.log(`Created new KC user ${keycloakUserId}`);
      }
      await this.reportStep(provisioningId, 3);

      // ΓöÇΓöÇ Step 4: Add user to the organization ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      await this.keycloakAdminService.addUserToOrganization(
        keycloakOrgId!,
        keycloakUserId!,
      );
      await this.reportStep(provisioningId, 4);

      // ΓöÇΓöÇ Step 5: Create Tenant record in MongoDB ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      const tenantData: Partial<Tenant> = {
        keycloakOrgId: keycloakOrgId!,
        alias: data.alias,
        name: data.companyName,
        ownerId: null as any,
        subscriptionPlan: data.plan || SubscriptionPlan.FREE,
        status: TenantStatus.ACTIVE,
        provisioningStatus: ProvisioningStatus.PROVISIONING,
        onboardingGoal: data.useCase,
      };
      const spaceIdx = data.fullName.indexOf(' ');
      const firstName =
        spaceIdx > -1 ? data.fullName.slice(0, spaceIdx) : data.fullName;
      const lastName = spaceIdx > -1 ? data.fullName.slice(spaceIdx + 1) : '';

      const transactionalResult =
        await this.transactionManager.runInTransaction(async (session) => {
          const tenant = await this.tenantsRepository.create(
            tenantData,
            session,
          );

          const localUser = await this.userRepository.upsertWithTenants(
            keycloakUserId!,
            data.email,
            {
              firstName,
              lastName,
              provider: AuthProvidersEnum.email,
              platformRole: { id: PlatformRoleEnum.USER } as any,
              status: { id: StatusEnum.active } as any,
              keycloakId: keycloakUserId!,
              onboardingStatus: 'COMPLETED',
            },
            [{ tenantId: tenant.id, roles: ['OWNER'], joinedAt: new Date() }],
            session,
          );

          await this.tenantsRepository.updateOwner(
            tenant.id,
            localUser.id as string,
            session,
          );

          return { tenant, localUser };
        });

      const tenant = transactionalResult.tenant;
      const localUser = transactionalResult.localUser;
      tenantId = tenant.id;
      await this.reportStep(provisioningId, 5);
      await this.reportStep(provisioningId, 6);

      await this.reportStep(provisioningId, 7);

      // ΓöÇΓöÇ Step 8: Provision crm-bot Typebot workspace ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      const botWorkspaceId =
        await this.crmBotWorkspaceProvisioningService.provisionWorkspace({
          tenantId: tenantId!,
          ownerEmail: data.email,
          ownerName: data.fullName,
          tenantName: data.companyName,
        });
      await this.tenantsRepository.update(tenantId!, { botWorkspaceId } as any);
      await this.reportStep(provisioningId, 8);

      // ΓöÇΓöÇ Step 9: Confirm alias reservation ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      await this.aliasReservationRepository.confirm(data.alias);
      await this.reportStep(provisioningId, 9);

      // ΓöÇΓöÇ Step 10: Seed sample data (placeholder for Phase 3) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      // TODO: Implement sample data seeder based on data.useCase
      await this.reportStep(provisioningId, 10);

      // ΓöÇΓöÇ Mark provisioning as READY ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      await this.tenantsRepository.update(tenantId!, {
        provisioningStatus: ProvisioningStatus.READY,
      });

      const redirectUrl = this.getTenantLoginUrl(data.alias);

      await this.updateStatus(provisioningId, {
        status: 'READY',
        currentStep: TOTAL_STEPS,
        totalSteps: TOTAL_STEPS,
        stepLabel: 'Your workspace is ready!',
        tenantId: tenantId!,
        redirectUrl,
      });

      // ΓöÇΓöÇ Emit event for downstream listeners (CRM settings seeding, etc.)
      runWithTenantContext(this.cls, tenantId!, () =>
        this.eventEmitter.emit(
          'tenant.created',
          new TenantCreatedEvent(
            tenantId!,
            data.companyName,
            data.email,
            localUser.id as string,
            data.useCase,
          ),
        ),
      );

      this.logger.log(
        `[${source}] Provisioning complete for "${data.companyName}" ΓåÆ ${redirectUrl}`,
      );
    } catch (error: unknown) {
      // ΓöÇΓöÇ Saga Rollback (compensating transactions) ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
      const errMsg = error instanceof Error ? error.message : String(error);
      this.logger.error(
        `[${source}] Provisioning FAILED for "${data.companyName}": ${errMsg}`,
        error instanceof Error ? error.stack : undefined,
      );

      // Compensate in reverse order
      if (tenantId) {
        await this.safeRollback('Delete MongoDB tenant', () =>
          this.tenantsRepository.update(tenantId!, {
            provisioningStatus: ProvisioningStatus.FAILED,
            provisioningError: errMsg,
          } as any),
        );
      }

      if (keycloakOrgId) {
        await this.safeRollback('Delete KC org', () =>
          this.keycloakAdminService.deleteOrganization(keycloakOrgId!),
        );
      }

      if (keycloakUserCreatedByThisJob && keycloakUserId) {
        await this.safeRollback('Delete KC user', () =>
          this.keycloakAdminService.deleteUser(keycloakUserId!),
        );
      }

      if (aliasReserved) {
        await this.safeRollback('Delete alias reservation', () =>
          this.aliasReservationRepository.delete(data.alias),
        );
      }

      await this.updateStatus(provisioningId, {
        status: 'FAILED',
        currentStep: 0,
        totalSteps: TOTAL_STEPS,
        stepLabel: 'Provisioning failed',
        error: 'Workspace setup failed. Our team has been notified.',
        retryable: (job.attemptsMade ?? 0) < (job.opts?.attempts ?? 3),
      });

      throw error; // Let BullMQ handle retry
    }
  }

  // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ
  // Helpers
  // ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

  private async reportStep(
    provisioningId: string,
    step: number,
  ): Promise<void> {
    this.logger.log(
      `[Step ${step}/${TOTAL_STEPS}] ${STEP_LABELS[step] || 'ΓÇª'}`,
    );
    await this.updateStatus(provisioningId, {
      status: 'PROVISIONING',
      currentStep: step,
      totalSteps: TOTAL_STEPS,
      stepLabel: STEP_LABELS[step] || 'ProcessingΓÇª',
    });
  }

  private async updateStatus(
    provisioningId: string,
    payload: ProvisioningStatusPayload,
  ): Promise<void> {
    // 1. DB-first: MongoDB is the source of truth for history/audit.
    try {
      await this.provisioningJobRepository.updateStatus(provisioningId, {
        status: payload.status,
        currentStep: payload.currentStep,
        totalSteps: payload.totalSteps,
        stepLabel: payload.stepLabel,
        tenantId: payload.tenantId,
        redirectUrl: payload.redirectUrl,
        error: payload.error,
      });
    } catch (dbErr) {
      // Log but do not block ΓÇö Redis and webhook writes still proceed
      this.logger.error(
        `[DB] Failed to persist provisioning status for ${provisioningId}: ${dbErr instanceof Error ? dbErr.message : dbErr}`,
      );
    }

    // 2. Redis cache for low-latency polling fallback
    const key = `${PROVISIONING_KEY_PREFIX}${provisioningId}`;
    await this.redisService.set(key, JSON.stringify(payload), PROVISIONING_TTL);

    // 3. Push realtime event to crm-manager-api WebSocket gateway (fire-and-forget)
    void this.notifyManagerGateway(provisioningId, payload);
  }

  private async notifyManagerGateway(
    provisioningId: string,
    payload: ProvisioningStatusPayload,
  ): Promise<void> {
    const webhookUrl = (this.configService as ConfigService).get<string>(
      'MANAGER_API_INTERNAL_WEBHOOK_URL',
    );
    if (!webhookUrl) return;

    const internalApiKey = (this.configService as ConfigService).get<string>(
      'INTERNAL_API_KEY',
    );

    try {
      const controller = new AbortController();
      const timeout = setTimeout(() => controller.abort(), 3_000);
      await fetch(`${webhookUrl}/api/onboarding/internal/provisioning-events`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          ...(internalApiKey ? { 'X-Internal-Api-Key': internalApiKey } : {}),
        },
        body: JSON.stringify({ provisioningId, ...payload }),
        signal: controller.signal,
      }).finally(() => clearTimeout(timeout));
    } catch {
      // Non-critical ΓÇö polling or WebSocket reconnect will hydrate state
    }
  }

  private async safeRollback(
    label: string,
    fn: () => Promise<any>,
  ): Promise<void> {
    try {
      await fn();
      this.logger.warn(`[Rollback] ${label} ΓÇö OK`);
    } catch (e: unknown) {
      this.logger.error(
        `[Rollback] ${label} ΓÇö FAILED: ${e instanceof Error ? e.message : e}`,
      );
    }
  }

  private getTenantLoginUrl(alias: string): string {
    const frontendUrl =
      this.configService.get('keycloak.frontendUrl', { infer: true }) ||
      'https://crmsaudi.dev';
    const rootDomain =
      this.configService.get('app.rootDomain', { infer: true }) ||
      'crmsaudi.dev';
    const url = new URL(frontendUrl);
    url.hostname = `${alias}.${rootDomain}`;
    url.pathname = '/login';
    url.search = '';
    url.hash = '';
    return url.toString();
  }

  private generateTempPassword(): string {
    // SLG flow: user will reset via Keycloak executeActionsEmail
    return `Temp${ulid().slice(-12)}!`;
  }
}

import mongoose, { Schema, Model, Connection, Document } from 'mongoose';
import { ConflictException } from '@nestjs/common';
import {
  setupTestDatabase,
  clearDatabase,
  teardownTestDatabase,
} from './integration-setup';
import { runWithTenant } from './helpers/cls-context.helper';
import { tenantFilterPlugin } from '../common/plugins/tenant-filter.plugin';
import { BaseDocumentRepository } from '../utils/persistence/document-repository.abstract';
import { ClsServiceManager } from 'nestjs-cls';

/**
 * BaseDocumentRepository ΓÇö INTEGRATION TESTS with real MongoDB
 *
 * Tests the REAL PATCH semantics, version conflicts, and tenant enrichment.
 * These are the highest-risk behaviors because they affect ALL entities
 * (contacts, tickets, deals, accounts) through the shared base class.
 *
 * Dangerous bugs this catches:
 * - PATCH overwrites fields not in the payload (e.g. phones ΓåÆ [])
 * - Version conflict not detected ΓåÆ data loss from concurrent edits
 * - Tenant enrichment missing ΓåÆ cross-tenant data creation
 */

// ΓöÇΓöÇΓöÇ Minimal test schema ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

interface TestEntity {
  id: string;
  tenantId: string;
  name: string;
  emails: string[];
  phones: string[];
  score: number;
  ownerId?: string;
  createdById: string;
  updatedById: string;
  version?: number;
}

const TestEntitySchema = new Schema(
  {
    tenantId: { type: Schema.Types.ObjectId, required: true, index: true },
    name: { type: String, required: true },
    emails: { type: [String], default: [] },
    phones: { type: [String], default: [] },
    score: { type: Number, default: 0 },
    ownerId: { type: Schema.Types.ObjectId },
    createdById: { type: Schema.Types.ObjectId, required: true },
    updatedById: { type: Schema.Types.ObjectId, required: true },
  },
  { timestamps: true },
);
TestEntitySchema.plugin(tenantFilterPlugin, { field: 'tenantId' });

type TestEntityDocument = Document & {
  tenantId: string;
  name: string;
  emails: string[];
  phones: string[];
  score: number;
  ownerId?: string;
  createdById: string;
  updatedById: string;
};

// ΓöÇΓöÇΓöÇ Concrete repository for testing ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

class TestEntityRepository extends BaseDocumentRepository<
  TestEntityDocument,
  TestEntity
> {
  protected mapToDomain(doc: any): TestEntity {
    return {
      id: doc._id?.toString(),
      tenantId: doc.tenantId?.toString(),
      name: doc.name,
      emails: doc.emails ?? [],
      phones: doc.phones ?? [],
      score: doc.score ?? 0,
      ownerId: doc.ownerId?.toString(),
      createdById: doc.createdById?.toString(),
      updatedById: doc.updatedById?.toString(),
      version: doc.__v,
    };
  }

  protected toPersistence(domain: TestEntity): any {
    return {
      tenantId: domain.tenantId,
      name: domain.name,
      emails: domain.emails ?? [], // THIS is the dangerous default
      phones: domain.phones ?? [], // THIS is the dangerous default
      score: domain.score ?? 0,
      ownerId: domain.ownerId,
      createdById: domain.createdById,
      updatedById: domain.updatedById,
      __v: domain.version,
    };
  }
}

let connection: Connection;
let TestModel: Model<TestEntityDocument>;
let repo: TestEntityRepository;

const TENANT_A = new mongoose.Types.ObjectId().toString();
const TENANT_B = new mongoose.Types.ObjectId().toString();
const USER_1 = new mongoose.Types.ObjectId().toString();
const USER_2 = new mongoose.Types.ObjectId().toString();

beforeAll(async () => {
  connection = await setupTestDatabase();
  TestModel = connection.model('TestEntity', TestEntitySchema) as any;
}, 30000);

afterEach(async () => {
  await clearDatabase();
});

afterAll(async () => {
  await teardownTestDatabase();
}, 10000);

describe('BaseDocumentRepository ΓÇö real MongoDB', () => {
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // PATCH SEMANTICS ΓÇö the #1 data corruption risk
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  describe('PATCH semantics (update only submitted fields)', () => {
    it('updating name should NOT overwrite existing emails/phones with empty arrays', async () => {
      // Create entity with real data
      const created = await runWithTenant(TENANT_A, async () => {
        const cls = ClsServiceManager.getClsService();
        repo = new TestEntityRepository(TestModel, cls);
        return repo.create({
          name: 'John Doe',
          emails: ['john@example.com', 'john2@example.com'],
          phones: ['+84901234567'],
          score: 85,
        } as any);
      });

      // PATCH: only update name ΓÇö emails, phones, score should be UNTOUCHED
      const updated = await runWithTenant(TENANT_A, async () => {
        const cls = ClsServiceManager.getClsService();
        repo = new TestEntityRepository(TestModel, cls);
        return repo.update(created.id, { name: 'Jane Doe' } as any);
      });

      expect(updated!.name).toBe('Jane Doe');
      // CRITICAL: these must NOT be overwritten to empty defaults
      expect(updated!.emails).toEqual([
        'john@example.com',
        'john2@example.com',
      ]);
      expect(updated!.phones).toEqual(['+84901234567']);
      expect(updated!.score).toBe(85);
    });

    it('updating score should NOT touch name or emails', async () => {
      const created = await runWithTenant(TENANT_A, async () => {
        const cls = ClsServiceManager.getClsService();
        repo = new TestEntityRepository(TestModel, cls);
        return repo.create({
          name: 'Contact A',
          emails: ['a@test.com'],
          score: 50,
        } as any);
      });

      const updated = await runWithTenant(TENANT_A, async () => {
        const cls = ClsServiceManager.getClsService();
        repo = new TestEntityRepository(TestModel, cls);
        return repo.update(created.id, { score: 99 } as any);
      });

      expect(updated!.score).toBe(99);
      expect(updated!.name).toBe('Contact A');
      expect(updated!.emails).toEqual(['a@test.com']);
    });
  });

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // VERSION CONFLICT ΓÇö concurrent edit detection
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  describe('optimistic locking (version conflict)', () => {
    it('concurrent update with stale version throws ConflictException', async () => {
      const created = await runWithTenant(TENANT_A, async () => {
        const cls = ClsServiceManager.getClsService();
        repo = new TestEntityRepository(TestModel, cls);
        return repo.create({ name: 'Original', emails: ['x@y.com'] } as any);
      });

      // User 1 updates (version 0 ΓåÆ 1)
      await runWithTenant(TENANT_A, async () => {
        const cls = ClsServiceManager.getClsService();
        repo = new TestEntityRepository(TestModel, cls);
        return repo.update(created.id, {
          name: 'User1 Edit',
          version: 0,
        } as any);
      });

      // User 2 tries with stale version 0 ΓåÆ should throw
      await expect(
        runWithTenant(TENANT_A, async () => {
          const cls = ClsServiceManager.getClsService();
          repo = new TestEntityRepository(TestModel, cls);
          return repo.update(created.id, {
            name: 'User2 Edit',
            version: 0,
          } as any);
        }),
      ).rejects.toThrow(ConflictException);
    });
  });

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // TENANT ENRICHMENT ΓÇö auto-set from CLS
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  describe('tenant auto-enrichment', () => {
    it('create() auto-sets tenantId, createdById, ownerId from CLS', async () => {
      const created = await runWithTenant(TENANT_A, async () => {
        const cls = ClsServiceManager.getClsService();
        cls.set('userId', USER_1);
        repo = new TestEntityRepository(TestModel, cls);
        return repo.create({ name: 'Auto-enriched' } as any);
      });

      expect(created.tenantId).toBe(TENANT_A);
      expect(created.createdById).toBe(USER_1);
      expect(created.updatedById).toBe(USER_1);
      // ownerId auto-assigned to creator
      expect(created.ownerId).toBe(USER_1);
    });

    it('create() does NOT overwrite explicitly set tenantId', async () => {
      const created = await runWithTenant(TENANT_A, async () => {
        const cls = ClsServiceManager.getClsService();
        repo = new TestEntityRepository(TestModel, cls);
        return repo.create({
          name: 'Explicit tenant',
          tenantId: TENANT_A, // explicitly set
        } as any);
      });

      expect(created.tenantId).toBe(TENANT_A);
    });

    it('update() auto-enriches updatedById from CLS', async () => {
      const created = await runWithTenant(TENANT_A, async () => {
        const cls = ClsServiceManager.getClsService();
        cls.set('userId', USER_1);
        repo = new TestEntityRepository(TestModel, cls);
        return repo.create({ name: 'By User1' } as any);
      });

      // Different user updates
      const updated = await runWithTenant(TENANT_A, async () => {
        const cls = ClsServiceManager.getClsService();
        cls.set('userId', USER_2);
        repo = new TestEntityRepository(TestModel, cls);
        return repo.update(created.id, { name: 'Updated by User2' } as any);
      });

      expect(updated!.updatedById).toBe(USER_2);
      expect(updated!.createdById).toBe(USER_1); // creator unchanged
    });
  });

  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  // CROSS-TENANT UPDATE/DELETE PROTECTION
  // ΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉΓòÉ
  describe('cross-tenant protection', () => {
    it('update() from different tenant returns null (no match)', async () => {
      const created = await runWithTenant(TENANT_A, async () => {
        const cls = ClsServiceManager.getClsService();
        repo = new TestEntityRepository(TestModel, cls);
        return repo.create({ name: 'TenantA Data', score: 50 } as any);
      });

      const result = await runWithTenant(TENANT_B, async () => {
        const cls = ClsServiceManager.getClsService();
        repo = new TestEntityRepository(TestModel, cls);
        return repo.update(created.id, { name: 'Hacked' } as any);
      });

      expect(result).toBeNull();

      // Original unchanged
      const original = await runWithTenant(TENANT_A, async () => {
        const cls = ClsServiceManager.getClsService();
        repo = new TestEntityRepository(TestModel, cls);
        return repo.findOne({ _id: created.id } as any);
      });
      expect(original!.name).toBe('TenantA Data');
    });

    it('remove() from different tenant has no effect', async () => {
      const created = await runWithTenant(TENANT_A, async () => {
        const cls = ClsServiceManager.getClsService();
        repo = new TestEntityRepository(TestModel, cls);
        return repo.create({ name: 'Protected' } as any);
      });

      await runWithTenant(TENANT_B, async () => {
        const cls = ClsServiceManager.getClsService();
        repo = new TestEntityRepository(TestModel, cls);
        await repo.remove(created.id);
      });

      const stillExists = await runWithTenant(TENANT_A, async () => {
        const cls = ClsServiceManager.getClsService();
        repo = new TestEntityRepository(TestModel, cls);
